-- Schema for Domain: compliance | Business: Staffing Hr | Version: v1_mvm
-- Generated on: 2026-05-02 22:45:36

-- ========= DATABASE =========
CREATE DATABASE IF NOT EXISTS `staffing_hr_ecm_v1`.`compliance` COMMENT 'Owns regulatory and legal compliance data across the entire workforce lifecycle. Covers I-9 verification, E-Verify, EEOC compliance and reporting, OFCCP reporting, FLSA worker classification determinations (W-2 vs 1099), co-employment and joint employment risk management, non-compete and NDA enforcement tracking, OSHA safety compliance, audit trails required by DOL, OSHA, and IRS regulatory frameworks. Ensures all placements meet federal, state, and client-specific compliance requirements.';

-- ========= TABLES =========
CREATE OR REPLACE TABLE `staffing_hr_ecm_v1`.`compliance`.`i9_verification` (
    `i9_verification_id` BIGINT COMMENT 'Unique system-generated identifier for each I-9 Employment Eligibility Verification record. Primary key for this entity. TRANSACTION_HEADER role — master record for I-9 compliance per INA requirements.',
    `assignment_id` BIGINT COMMENT 'Reference to the staffing placement or assignment associated with this I-9 verification. Ties the I-9 record to the specific job placement triggering the eligibility check.',
    `msa_id` BIGINT COMMENT 'Foreign key linking to contract.msa. Business justification: MSAs specify I-9 and E-Verify requirements for client engagements, especially federal contractors. Compliance teams validate MSA terms during onboarding to ensure I-9 verification standards align with',
    `ic_agreement_id` BIGINT COMMENT 'Foreign key linking to contract.ic_agreement. Business justification: I-9 verification for IC workers is governed by the ic_agreements employment authorization requirements and employer_of_record designation. Staffing HR must link I-9 records to the IC agreement to det',
    `credential_instance_id` BIGINT COMMENT 'Foreign key linking to credentialing.credential_instance. Business justification: I-9 Section 2 List A document verification links to the actual credential instance record (passport, EAD, etc.). Business process: I-9 compliance audit trail requires reference to verified credential ',
    `profile_id` BIGINT COMMENT 'Reference to the worker (candidate/employee) for whom this I-9 verification was completed. Links to the worker/candidate master record in the onboarding system.',
    `sow_id` BIGINT COMMENT 'Foreign key linking to contract.sow. Business justification: SOW-specific engagements (e.g., federal projects) may require stricter I-9/E-Verify protocols beyond MSA baseline. Real business need: SOW-level compliance tracking for audit and client reporting.',
    `supplier_id` BIGINT COMMENT 'Foreign key linking to vendor.supplier. Business justification: Staffing firms use third-party I-9 verification vendors (E-Verify service providers, document authentication services). Track supplier for vendor performance monitoring, SLA compliance, audit trail, a',
    `work_authorization_id` BIGINT COMMENT 'Foreign key linking to credentialing.work_authorization. Business justification: I-9 verification directly validates the candidates work authorization documents (visa, EAD, I-94). The work_authorization product captures visa category, EAD card number, and I-94 — all verified duri',
    `alien_registration_number` STRING COMMENT 'USCIS Alien Registration Number (A-Number) provided by the employee in Section 1 when applicable. Required for lawful permanent residents and certain aliens authorized to work. Highly sensitive government-issued identifier.. Valid values are `^A[0-9]{8,9}$`',
    `authorized_representative_name` STRING COMMENT 'Full name of the employers authorized representative who physically examined the employees documents and completed Section 2 of the I-9 form. Required for audit trail and employer liability documentation.',
    `authorized_representative_title` STRING COMMENT 'Job title of the employers authorized representative who completed Section 2. Documents the authority level of the individual who performed the document inspection.',
    `case_number` STRING COMMENT 'Unique externally-known case reference number assigned to this I-9 verification record, often sourced from the onboarding workflow or Sterling BGC system. Used for audit trail and cross-system reconciliation.',
    `citizenship_status` STRING COMMENT 'Employees attested citizenship or immigration status as declared in Section 1 of the I-9 form. Determines document list requirements for Section 2 verification. Sensitive PII per USCIS and FCRA.. Valid values are `us_citizen|us_national|lawful_permanent_resident|alien_authorized_to_work`',
    `created_timestamp` TIMESTAMP COMMENT 'Timestamp when this I-9 verification record was first created in the system. Audit trail field required for DOL, OSHA, and IRS regulatory audit frameworks. Format: yyyy-MM-ddTHH:mm:ss.SSSXXX.',
    `document_issuing_authority` STRING COMMENT 'Name of the government agency or authority that issued the primary document used for verification (e.g., U.S. Department of State for passports, state DMV for drivers licenses, SSA for Social Security cards).',
    `employer_business_name` STRING COMMENT 'Legal business name of the employer (staffing firm or client company) recorded in Section 2 of the I-9. In co-employment or joint employment scenarios, this identifies which entity is the employer of record for I-9 purposes.',
    `employer_of_record_type` STRING COMMENT 'Identifies which entity type is acting as the Employer of Record (EOR) for I-9 compliance purposes. Critical in staffing and co-employment arrangements to determine I-9 responsibility. Values: staffing_firm (staffing agency is EOR), client_company (client is EOR), peo (Professional Employer Organization), eor (dedicated Employer of Record service).. Valid values are `staffing_firm|client_company|peo|eor`',
    `everify_case_number` STRING COMMENT 'Unique case number assigned by the DHS/SSA E-Verify system when the employer submits the I-9 information for electronic employment eligibility verification. Links this I-9 record to the corresponding E-Verify transaction.',
    `everify_final_result_date` DATE COMMENT 'Date on which the E-Verify case reached a final determination (Employment Authorized or Final Nonconfirmation). Used for compliance reporting and audit trail.',
    `everify_status` STRING COMMENT 'Current status of the E-Verify case associated with this I-9 verification. Tracks the electronic verification result from DHS/SSA. A Tentative Nonconfirmation (TNC) requires employee notification and contest opportunity.. Valid values are `not_submitted|pending|employment_authorized|tentative_nonconfirmation|final_nonconfirmation|case_in_continuance`',
    `everify_submission_date` DATE COMMENT 'Date on which the employer submitted the I-9 information to the E-Verify system. Must occur no later than 3 business days after the hire date per E-Verify program requirements.',
    `foreign_passport_country` STRING COMMENT 'ISO 3166-1 alpha-3 country code for the country that issued the foreign passport referenced in Section 1. Required when a foreign passport number is provided.. Valid values are `^[A-Z]{3}$`',
    `foreign_passport_number` STRING COMMENT 'Foreign passport number provided by the employee in Section 1 when applicable, along with the country of issuance. Used for aliens authorized to work who provide a foreign passport with Form I-94.',
    `hire_date` DATE COMMENT 'The date the worker was hired or the assignment commenced. Section 1 of the I-9 must be completed no later than the first day of employment; Section 2 must be completed within 3 business days of this date.',
    `i94_admission_number` STRING COMMENT 'CBP Form I-94 Arrival/Departure Record number provided by the employee in Section 1 when applicable. Used for aliens authorized to work who do not have an A-Number or foreign passport with visa.',
    `list_a_document_number` STRING COMMENT 'Document number from the List A identity and employment authorization document presented in Section 2. Recorded by the employer/authorized representative during physical document inspection.',
    `list_a_document_type` STRING COMMENT 'Type of List A document (establishes both identity and employment authorization) presented by the employee in Section 2. Examples include U.S. Passport, Permanent Resident Card (I-551), Employment Authorization Document (I-766). Mutually exclusive with List B/C combination. [ENUM-REF-CANDIDATE: us_passport|us_passport_card|permanent_resident_card|alien_registration_receipt_card|employment_auth_document|foreign_passport_i94|foreign_passport_i551|passport_i94_i20|passport_i94_ds2019 — promote to reference product]',
    `list_a_expiration_date` DATE COMMENT 'Expiration date of the List A document as recorded in Section 2. Used to determine reverification requirements. Null if the document has no expiration date.',
    `list_b_document_number` STRING COMMENT 'Document number from the List B identity document presented in Section 2. Recorded by the employer/authorized representative during physical document inspection.',
    `list_b_document_type` STRING COMMENT 'Type of List B document (establishes identity only) presented by the employee in Section 2 when no List A document is provided. Examples include drivers license, state ID card, school ID with photo. Must be used in combination with a List C document. [ENUM-REF-CANDIDATE: drivers_license|state_id|school_id_photo|voter_registration|us_military_card|military_dependent_id|us_coast_guard_id|native_american_tribal_doc|canadian_drivers_license — promote to reference product]',
    `list_b_expiration_date` DATE COMMENT 'Expiration date of the List B document as recorded in Section 2. Null if the document has no expiration date.',
    `list_c_document_number` STRING COMMENT 'Document number from the List C employment authorization document presented in Section 2. Recorded by the employer/authorized representative during physical document inspection.',
    `list_c_document_type` STRING COMMENT 'Type of List C document (establishes employment authorization only) presented by the employee in Section 2 when no List A document is provided. Examples include Social Security card, birth certificate, employment authorization issued by DHS. Must be used in combination with a List B document. [ENUM-REF-CANDIDATE: social_security_card|us_birth_certificate|us_citizen_id_card|native_american_tribal_doc|us_id_card_for_use_in_us|dhs_employment_auth — promote to reference product]',
    `list_c_expiration_date` DATE COMMENT 'Expiration date of the List C document as recorded in Section 2. Null if the document has no expiration date.',
    `onboarding_source_system` STRING COMMENT 'Identifies the operational system from which this I-9 record was sourced or initiated. Supports data lineage and reconciliation between SAP SuccessFactors onboarding workflows and Sterling BGC verification system.. Valid values are `sap_successfactors|sterling_bgc|bullhorn|manual`',
    `preparer_used` BOOLEAN COMMENT 'Indicates whether a preparer or translator assisted the employee in completing Section 1 of the I-9 form. When True, the preparer/translator certification fields must also be completed.',
    `remote_verification` BOOLEAN COMMENT 'Indicates whether the I-9 document examination was conducted remotely using the DHS-authorized alternative procedure (video link, fax, or email) rather than in-person physical inspection. Remote verification requires additional documentation and is subject to specific DHS authorization.',
    `reverification_due_date` DATE COMMENT 'Date by which Section 3 reverification must be completed to maintain continuous employment authorization compliance. Typically set to the work authorization expiration date or document expiration date, whichever is earlier.',
    `reverification_required` BOOLEAN COMMENT 'Indicates whether this I-9 record requires reverification of employment authorization documents before the work authorization expiration date. Drives compliance workflow alerts and Section 3 completion.',
    `section1_completed_date` DATE COMMENT 'Date on which the employee completed and signed Section 1 (Employee Information and Attestation) of the I-9 form. Must be completed no later than the first day of employment per INA requirements.',
    `section2_completed_date` DATE COMMENT 'Date on which the employer or authorized representative completed Section 2 (Employer or Authorized Representative Review and Verification) of the I-9 form. Must be completed within 3 business days of the hire date.',
    `section3_completed_date` DATE COMMENT 'Date on which Section 3 (Reverification and Rehires) was completed. Populated when a worker is rehired within 3 years of the original I-9 date or when work authorization documents require reverification.',
    `source_record_reference` STRING COMMENT 'The native record identifier from the originating source system (SAP SuccessFactors, Sterling BGC, or Bullhorn) for this I-9 record. Enables cross-system reconciliation and data lineage tracing in the Silver layer.',
    `tnc_contested` BOOLEAN COMMENT 'Indicates whether the employee chose to contest the Tentative Nonconfirmation (TNC). If True, the employee has 8 federal government working days to contact SSA or DHS to resolve the discrepancy.',
    `tnc_issued` BOOLEAN COMMENT 'Indicates whether a Tentative Nonconfirmation (TNC) was issued by E-Verify for this case. When True, the employer must notify the employee and provide the Further Action Notice. Triggers a mandatory contest window.',
    `tnc_notification_date` DATE COMMENT 'Date on which the employer notified the employee of the Tentative Nonconfirmation (TNC) result. Employer must notify the employee promptly and cannot take adverse action during the contest period.',
    `updated_timestamp` TIMESTAMP COMMENT 'Timestamp when this I-9 verification record was last modified. Supports audit trail requirements and change detection in the Silver layer lakehouse. Format: yyyy-MM-ddTHH:mm:ss.SSSXXX.',
    `verification_status` STRING COMMENT 'Current lifecycle status of the I-9 verification record. Tracks progression from initial employee attestation through employer document review to final closure or reverification. [ENUM-REF-CANDIDATE: pending|section1_complete|section2_complete|reverification_required|closed|cancelled — promote to reference product if additional statuses are needed]. Valid values are `pending|section1_complete|section2_complete|reverification_required|closed|cancelled`',
    `work_auth_expiration_date` DATE COMMENT 'Date on which the employees work authorization expires as attested in Section 1. Drives reverification scheduling. Null for U.S. citizens, nationals, and lawful permanent residents with no expiration.',
    CONSTRAINT pk_i9_verification PRIMARY KEY(`i9_verification_id`)
) COMMENT 'Master record for I-9 Employment Eligibility Verification for each worker. Tracks Section 1 (employee attestation), Section 2 (employer document review), Section 3 (reverification/rehire), document types presented, document numbers, expiration dates, E-Verify case number linkage, completion status, and re-verification due dates. SSOT for I-9 compliance per INA requirements. Sourced from onboarding workflows and Sterling BGC system.';

CREATE OR REPLACE TABLE `staffing_hr_ecm_v1`.`compliance`.`everify_case` (
    `everify_case_id` BIGINT COMMENT 'Unique surrogate identifier for each E-Verify case record in the Staffing Hr compliance data product. Primary key for the everify_case table in the Silver Layer lakehouse.',
    `assignment_id` BIGINT COMMENT 'Reference to the staffing placement or assignment record for which this E-Verify case was initiated. Connects compliance verification to the specific job placement in Bullhorn ATS.',
    `msa_id` BIGINT COMMENT 'Foreign key linking to contract.msa. Business justification: E-Verify requirements are contractually mandated in MSAs, especially for federal contractors. Audit trail links E-Verify cases to MSA obligations for compliance reporting and client verification.',
    `i9_verification_id` BIGINT COMMENT 'Reference to the associated I-9 Employment Eligibility Verification record that triggered this E-Verify case submission. Links the E-Verify case to the underlying I-9 form completed during onboarding.',
    `ic_agreement_id` BIGINT COMMENT 'Foreign key linking to contract.ic_agreement. Business justification: E-Verify cases for IC workers are tied to the ic_agreements everify obligations and employer_of_record designation. Staffing compliance teams must link E-Verify cases to the governing IC agreement to',
    `profile_id` BIGINT COMMENT 'Reference to the candidate (worker) whose employment eligibility is being verified through this E-Verify case. Sourced from Bullhorn ATS candidate record.',
    `sow_id` BIGINT COMMENT 'Foreign key linking to contract.sow. Business justification: SOW-level E-Verify requirements (e.g., specific federal projects) drive case creation. Real business need: SOW compliance reporting and client-specific E-Verify audit trails.',
    `supplier_id` BIGINT COMMENT 'Foreign key linking to vendor.supplier. Business justification: E-Verify cases may be processed by third-party compliance vendors or managed service providers. Track supplier for SLA monitoring, dispute resolution, case quality assessment, and vendor invoice recon',
    `vendor_agreement_id` BIGINT COMMENT 'Foreign key linking to contract.vendor_agreement. Business justification: E-Verify cases for vendor-supplied workers are governed by the vendor_agreements everify_required_flag and federal_contractor_flag. Staffing compliance teams must link E-Verify cases to the vendor_ag',
    `credential_instance_id` BIGINT COMMENT 'Foreign key linking to credentialing.credential_instance. Business justification: E-Verify cases validate specific work authorization documents tracked as credential instances. Business process: E-Verify document validation and photo match reference the actual credential instance b',
    `work_authorization_id` BIGINT COMMENT 'Foreign key linking to credentialing.work_authorization. Business justification: E-Verify cases are initiated to verify the work authorization documents submitted during I-9. The work_authorization product has everify_case_number as a plain attribute — a denormalization signal. Li',
    `case_closure_date` DATE COMMENT 'The date on which the E-Verify case was officially closed in the federal portal. Marks the end of the case lifecycle. Used for compliance reporting, audit trails, and calculating case processing duration.',
    `case_closure_reason` STRING COMMENT 'The business reason for closing the E-Verify case. Captures whether closure was due to authorization, final nonconfirmation, early termination, case error, or other administrative reasons. Required for federal audit trails and DOL regulatory reporting.. Valid values are `Employment Authorized|Final Nonconfirmation|Employee Terminated Prior to Resolution|Case Error|Duplicate Case|Other`',
    `case_status` STRING COMMENT 'Current lifecycle status of the E-Verify case as returned by the DHS/SSA federal portal. Drives compliance workflow actions including TNC resolution, referral, and closure processes. [ENUM-REF-CANDIDATE: Employment Authorized|Tentative Nonconfirmation|Final Nonconfirmation|Case in Continuance|Closed|DHS Verification in Process — promote to reference product]. Valid values are `Employment Authorized|Tentative Nonconfirmation|Final Nonconfirmation|Case in Continuance|Closed`',
    `case_verification_type` STRING COMMENT 'Classifies the type of E-Verify verification being performed. New Hire cases are standard; Rehire cases apply when a worker is rehired after a break in service; Federal Contractor cases apply under FAR E-Verify clause requirements for federal contract placements.. Valid values are `New Hire|Rehire|Federal Contractor`',
    `compliance_notes` STRING COMMENT 'Free-text field for compliance officers to document case-specific notes, exceptions, escalations, or remediation actions taken during the E-Verify process. Used for internal audit documentation and legal hold purposes. Sourced from Sterling BGC and manual compliance team entries.',
    `created_timestamp` TIMESTAMP COMMENT 'The timestamp when this E-Verify case record was first created in the Staffing Hr compliance data platform (Silver Layer). Represents the data ingestion audit trail timestamp, distinct from the case submission timestamp. Required for SOC 2 Type II audit controls.',
    `dhs_case_number` STRING COMMENT 'The official case number assigned by the DHS/SSA E-Verify federal portal upon case creation. This is the externally-known identifier used to track and reference the case with federal authorities. Sourced from Sterling BGC and E-Verify federal portal integration.. Valid values are `^[A-Z0-9]{13,20}$`',
    `document_title_list_used` STRING COMMENT 'Indicates whether the worker presented a List A document (establishes both identity and employment authorization) or a combination of List B (identity) and List C (employment authorization) documents during I-9 verification. Relevant to E-Verify case processing rules.. Valid values are `List A|List B and C`',
    `employee_first_day_of_work` DATE COMMENT 'The date the employee began work for pay at Staffing Hr or the client site. E-Verify cases must be submitted within 3 business days of this date per federal program rules. Used to validate timely submission compliance.',
    `employer_case_creator` STRING COMMENT 'The name or identifier of the Staffing Hr staff member (recruiter, onboarding specialist, or compliance officer) who created and submitted the E-Verify case. Required for internal audit trails and accountability tracking per SOC 2 Type II controls.',
    `employment_authorization_expiry_date` DATE COMMENT 'The expiration date of the workers employment authorization document as recorded in the E-Verify case. Triggers re-verification requirements for workers with temporary employment authorization. Critical for ongoing compliance monitoring and assignment management.',
    `federal_closure_code` STRING COMMENT 'The standardized federal closure code assigned by the DHS E-Verify portal upon case closure. Used for regulatory reporting, federal audit reconciliation, and compliance tracking with DHS and DOL requirements.. Valid values are `^[A-Z0-9]{1,10}$`',
    `federal_contractor_flag` BOOLEAN COMMENT 'Indicates whether this E-Verify case was submitted under the Federal Acquisition Regulation (FAR) E-Verify clause requirement for federal contractor placements. True = federal contractor case; False = standard commercial placement. Drives OFCCP compliance reporting.',
    `final_case_result` STRING COMMENT 'The conclusive result of the E-Verify case after all resolution steps (TNC contest, referral, continuance) have been completed. Used for final compliance determination and regulatory reporting to DOL and EEOC.. Valid values are `Employment Authorized|Final Nonconfirmation|Case Closed`',
    `further_action_notice_date` DATE COMMENT 'The date on which the Further Action Notice (FAN) was provided to the worker. Must be documented as part of the TNC resolution process. Null when no FAN was issued. Used for compliance audit trails and DOL regulatory reporting.',
    `further_action_notice_issued` BOOLEAN COMMENT 'Indicates whether a Further Action Notice (FAN) was issued to the worker as part of the TNC process. True = FAN was issued and provided to the worker; False = no FAN issued. Required documentation step for TNC compliance per DHS E-Verify program rules.',
    `initial_case_result` STRING COMMENT 'The first result returned by the E-Verify system upon initial case submission. Distinct from the final case status — captures the original determination before any TNC resolution or continuance. Key field for compliance audit trails required by DOL and IRS.. Valid values are `Employment Authorized|Tentative Nonconfirmation|DHS Verification in Process|SSA Tentative Nonconfirmation`',
    `late_submission_flag` BOOLEAN COMMENT 'Indicates whether the E-Verify case was submitted after the federally mandated 3-business-day window from the employees first day of work. True = late submission; False = timely submission. Used for compliance monitoring, SLA reporting, and DOL audit risk management.',
    `photo_match_result` STRING COMMENT 'The result of the E-Verify photo matching step, where the photo on the workers identity document is compared against DHS records. Applicable when the worker presents a document with a photo that E-Verify can match. Used for fraud detection and compliance documentation.. Valid values are `Match|No Match|Not Applicable`',
    `re_verification_required` BOOLEAN COMMENT 'Indicates whether the workers employment authorization requires re-verification before the expiry date. True = re-verification is required; False = no re-verification needed (e.g., U.S. citizen). Drives compliance workflow alerts for assignment managers.',
    `referral_agency` STRING COMMENT 'The federal agency (Social Security Administration or Department of Homeland Security) to which the worker was referred to resolve a Tentative Nonconfirmation (TNC). Determines the resolution process and timeline. Null or None when no referral was required.. Valid values are `SSA|DHS|SSA and DHS|None`',
    `referral_date` DATE COMMENT 'The date on which the worker was referred to the SSA or DHS to resolve a Tentative Nonconfirmation (TNC). Must occur within the federally mandated timeframe after TNC issuance. Null when no TNC referral was required. Tracked for DOL and DHS audit compliance.',
    `referral_deadline_date` DATE COMMENT 'The federally mandated deadline by which the worker must be referred to SSA or DHS to contest a Tentative Nonconfirmation (TNC). Calculated from the TNC issuance date per DHS E-Verify program rules. Used for SLA monitoring and compliance alerting.',
    `resolution_deadline_date` DATE COMMENT 'The federally mandated deadline by which the TNC must be resolved by the referring agency (SSA or DHS). Staffing Hr must not terminate employment before this date solely due to TNC status. Tracked for EEOC anti-discrimination compliance and DOL audit.',
    `source_system` STRING COMMENT 'Identifies the operational system of record from which this E-Verify case record was sourced. Supports data lineage tracking and reconciliation between Sterling Background Check integration and the DHS E-Verify federal portal.. Valid values are `Sterling BGC|E-Verify Portal|Manual Entry`',
    `sterling_case_reference` STRING COMMENT 'The case reference number assigned by Sterling Background Check system for this E-Verify submission. Used for reconciliation between Sterling BGC integration records and the DHS E-Verify federal portal. Enables cross-system audit trail.',
    `submission_timestamp` TIMESTAMP COMMENT 'The exact date and time when the E-Verify case was submitted to the DHS/SSA federal portal. This is the principal business event timestamp for the case. Must occur within 3 business days of the employees first day of work per federal E-Verify program rules.',
    `tnc_issuance_date` DATE COMMENT 'The date on which the Tentative Nonconfirmation (TNC) was issued by the E-Verify system. Triggers the mandatory referral and resolution timeline. Null when no TNC was issued. Critical for calculating referral and resolution deadlines.',
    `tnc_resolution_status` STRING COMMENT 'Tracks the workers response and resolution outcome for a Tentative Nonconfirmation (TNC). Indicates whether the worker contested the TNC, did not contest, and the resulting resolution. Null when no TNC was issued. Required for OFCCP and DOL compliance audit trails.. Valid values are `Pending|Contested|Not Contested|Resolved - Authorized|Resolved - Final Nonconfirmation`',
    `tnc_type` STRING COMMENT 'Identifies whether the Tentative Nonconfirmation (TNC) was issued by the Social Security Administration (SSA), the Department of Homeland Security (DHS), or both. Null or None when no TNC was issued. Drives the appropriate referral agency and resolution workflow.. Valid values are `SSA TNC|DHS TNC|SSA and DHS TNC|None`',
    `updated_timestamp` TIMESTAMP COMMENT 'The timestamp when this E-Verify case record was last modified in the Staffing Hr compliance data platform. Tracks all status changes, TNC updates, and closure events for audit trail purposes. Required for SOC 2 Type II and DOL audit compliance.',
    `worker_contested_tnc` BOOLEAN COMMENT 'Indicates whether the worker chose to contest the Tentative Nonconfirmation (TNC) with the issuing agency (SSA or DHS). True = worker contested; False = worker did not contest. Null when no TNC was issued. Critical for FLSA and EEOC anti-discrimination compliance.',
    CONSTRAINT pk_everify_case PRIMARY KEY(`everify_case_id`)
) COMMENT 'Transactional record for each E-Verify case submitted to DHS/SSA for worker employment eligibility confirmation. Captures case number, submission timestamp, initial case result (Employment Authorized, Tentative Nonconfirmation - TNC, Final Nonconfirmation), TNC resolution status, referral dates, closure reason, and federal case closure code. Links to i9_verification. Sourced from Sterling BGC and E-Verify federal portal integration.';

CREATE OR REPLACE TABLE `staffing_hr_ecm_v1`.`compliance`.`worker_classification` (
    `worker_classification_id` BIGINT COMMENT 'Unique system-generated identifier for each worker classification determination record. Primary key for the worker_classification data product.',
    `client_account_id` BIGINT COMMENT 'Reference to the client account associated with this worker engagement and classification determination. Relevant for co-employment and joint employment risk assessment.',
    `msa_id` BIGINT COMMENT 'Foreign key linking to contract.msa. Business justification: MSAs define permissible worker classifications (W-2, 1099, IC) and co-employment risk mitigation clauses. Classification decisions must align with MSA terms to avoid contractual breach and misclassifi',
    `credential_requirement_id` BIGINT COMMENT 'Foreign key linking to credentialing.credential_requirement. Business justification: Worker classification type (IC, W2, temp) determines which credential requirements apply during onboarding. Compliance officers link classification outcomes to credential requirement sets to trigger t',
    `ic_agreement_id` BIGINT COMMENT 'Foreign key linking to contract.ic_agreement. Business justification: IC classifications require corresponding IC agreements. Real business need: 1:1 mapping between classification determination and executed IC contract for audit trail and misclassification defense.',
    `location_id` BIGINT COMMENT 'Foreign key linking to client.location. Business justification: Worker classification determinations are jurisdiction-specific — the work location determines which state ABC test, IC test, or FLSA exemption applies. Linking worker_classification to location enable',
    `order_header_id` BIGINT COMMENT 'Foreign key linking to joborder.order_header. Business justification: Worker classification determinations (W2 vs 1099, employee vs IC) are often made during job order intake based on client requirements, job structure, and MSA terms. Links classification decisions to o',
    `position_requirement_id` BIGINT COMMENT 'Foreign key linking to joborder.position_requirement. Business justification: Worker classification determinations are made against specific position requirements that define the worker_classification type. Compliance officers trace misclassification risk back to the position_r',
    `profile_id` BIGINT COMMENT 'Reference to the worker (candidate or placed employee) whose classification is being determined. Links to the candidate or worker master record.',
    `sow_id` BIGINT COMMENT 'Foreign key linking to contract.sow. Business justification: SOWs specify engagement types (temp, temp-to-perm, IC) that drive classification. Real business need: SOW-driven classification validation ensures compliance with engagement-specific terms.',
    `state_compliance_rule_id` BIGINT COMMENT 'Foreign key linking to compliance.state_compliance_rule. Business justification: Worker classification determinations follow state-specific rules (ABC test, IC tests vary by state). This normalizes state_law_jurisdiction which can be retrieved via JOIN to state_compliance_rule. Cl',
    `supplier_id` BIGINT COMMENT 'Foreign key linking to vendor.supplier. Business justification: Worker classification determinations (IC vs. W-2) often require external legal counsel or compliance advisory firms. Track supplier for audit defense preparation, cost allocation to client/engagement,',
    `vendor_agreement_id` BIGINT COMMENT 'Foreign key linking to contract.vendor_agreement. Business justification: Worker classification determinations for vendor-supplied workers must reference the vendor_agreements tier_classification and contractual terms. Staffing compliance teams performing ABC test and beha',
    `abc_test_applicable` BOOLEAN COMMENT 'Indicates whether the state-level ABC Test (stricter than IRS Common Law Test) applies to this classification determination based on the work jurisdiction. True = ABC Test governs; False = IRS Common Law or DOL Economic Realities Test applies.',
    `abc_test_result` STRING COMMENT 'Outcome of the ABC Test evaluation where applicable. Pass = worker qualifies as independent contractor under all three prongs; Fail = worker must be classified as W-2 employee; Not Applicable = ABC Test does not govern this jurisdiction.. Valid values are `pass|fail|not_applicable`',
    `behavioral_control_score` STRING COMMENT 'Numeric score (0–100) reflecting the degree of behavioral control the staffing firm or client exercises over the worker, per the IRS Common Law Test. Higher scores indicate greater control and stronger W-2 classification support.',
    `classification_number` STRING COMMENT 'Externally-known unique business identifier for this classification determination record, used in audit correspondence, legal filings, and IRS inquiries. Format: WC-YYYY-NNNNNN.. Valid values are `^WC-[0-9]{4}-[0-9]{6}$`',
    `classification_status` STRING COMMENT 'Current lifecycle status of this classification determination. Pending = under review; Active = in force; Superseded = replaced by a newer determination; Appealed = under formal challenge; Revoked = withdrawn due to error or legal order.. Valid values are `pending|active|superseded|appealed|revoked`',
    `classification_type` STRING COMMENT 'The determined classification type for the worker engagement. W2 = W-2 employee (temporary or permanent); 1099_IC = Independent Contractor (1099-MISC); 1099_NEC = Non-Employee Compensation contractor; C2C = Corp-to-Corp engagement; EOR = Employer of Record arrangement. This is the SSOT for IC vs. W-2 decisions.. Valid values are `W2|1099_IC|1099_NEC|C2C|EOR`',
    `client_requested_classification` STRING COMMENT 'The worker classification type explicitly requested by the client in the job order, MSA, or SOW. May differ from the compliance-determined classification. Used to track client preference vs. legal determination and flag misalignment.. Valid values are `W2|1099_IC|C2C|EOR|no_preference`',
    `compliance_notes` STRING COMMENT 'Free-text field for compliance officers or legal counsel to document additional observations, risk factors, remediation actions, or contextual information relevant to this classification determination. Retained for audit trail.',
    `created_timestamp` TIMESTAMP COMMENT 'Timestamp when this worker classification record was first created in the system. Audit trail field required for DOL, IRS, and SOC 2 compliance.',
    `determination_basis` STRING COMMENT 'The legal or regulatory test framework used to arrive at the classification determination. Behavioral Control = IRS test on instruction/training; Financial Control = IRS test on investment/profit/loss; Relationship Type = IRS test on written contracts/benefits/permanency; ABC Test = state-level test (e.g., California AB5); Economic Realities = DOL FLSA test; Multi-Factor = combination of tests applied.. Valid values are `behavioral_control|financial_control|relationship_type|abc_test|economic_realities|multi_factor`',
    `determination_date` DATE COMMENT 'The date on which the formal worker classification determination was made and recorded. This is the principal business event date for this record.',
    `effective_from` DATE COMMENT 'The date from which this classification determination is binding and in effect for the worker engagement. May differ from determination_date if retroactive or prospective.',
    `effective_until` DATE COMMENT 'The date on which this classification determination expires or is superseded. Null for open-ended classifications. Populated when a new determination replaces this one or the engagement ends.',
    `financial_control_score` STRING COMMENT 'Numeric score (0–100) reflecting the degree of financial control the staffing firm or client exercises over the worker, per the IRS Common Law Test. Considers investment in tools, opportunity for profit/loss, and services available to the general market.',
    `flsa_exemption_status` STRING COMMENT 'FLSA overtime exemption classification for W-2 employees. Non-Exempt = entitled to overtime pay; Exempt categories follow the FLSA white-collar exemption tests (Executive, Administrative, Professional, Highly Compensated, Outside Sales). Drives OT and DT pay rule application. [ENUM-REF-CANDIDATE: non_exempt|exempt_executive|exempt_administrative|exempt_professional|exempt_highly_compensated|exempt_outside_sales — promote to reference product]. Valid values are `non_exempt|exempt_executive|exempt_administrative|exempt_professional|exempt_highly_compensated|exempt_outside_sales`',
    `ic_agreement_date` DATE COMMENT 'Date on which the Independent Contractor Agreement was executed. Used to verify agreement predates the engagement start and is current for the classification period.',
    `ic_agreement_on_file` BOOLEAN COMMENT 'Indicates whether a signed Independent Contractor Agreement is on file for this worker engagement. Required for 1099/IC classifications. Absence of a signed agreement increases misclassification risk.',
    `irs_audit_exposure_notes` STRING COMMENT 'Free-text field capturing compliance officer or attorney notes regarding IRS audit exposure risk for this classification. Documents specific factors that could attract IRS scrutiny, misclassification penalties, or back-tax liability under IRC Section 3509.',
    `misclassification_risk_level` STRING COMMENT 'Overall assessed risk level that the current classification determination could be challenged or reversed by the IRS, DOL, or state labor authority. Drives compliance monitoring frequency and legal review escalation.. Valid values are `low|medium|high|critical`',
    `nda_on_file` BOOLEAN COMMENT 'Indicates whether a signed Non-Disclosure Agreement (NDA) is on file for this worker engagement. Tracked as part of the compliance documentation package for the classification record.',
    `non_compete_on_file` BOOLEAN COMMENT 'Indicates whether a signed Non-Compete Agreement is on file for this worker. Relevant to classification because non-compete clauses are more consistent with employee relationships and may affect IC classification defensibility.',
    `override_flag` BOOLEAN COMMENT 'Indicates whether the final classification determination overrides the system-recommended or compliance-officer-recommended classification. True = an override was applied; False = determination follows standard process. Triggers mandatory documentation and senior review.',
    `override_reason` STRING COMMENT 'Free-text explanation documenting the business or legal justification for overriding the standard classification recommendation. Required when override_flag is True. Retained for audit trail and IRS inquiry response.',
    `previous_classification_type` STRING COMMENT 'The prior classification type for this worker on this engagement, captured when a reclassification event occurs. Enables audit trail of classification changes and supports IRS back-period liability analysis.. Valid values are `W2|1099_IC|1099_NEC|C2C|EOR|none`',
    `reclassification_date` DATE COMMENT 'Date on which a workers classification was changed from a prior type to the current classification_type. Null if this is the original classification with no prior change.',
    `reclassification_trigger` STRING COMMENT 'The event or authority that triggered a reclassification of the worker. Captures whether the change was driven by an IRS audit, DOL investigation, state labor audit, client request, proactive internal compliance review, legal counsel advice, or court order. [ENUM-REF-CANDIDATE: irs_audit|dol_audit|state_audit|client_request|internal_review|legal_counsel|court_order — 7 candidates stripped; promote to reference product]',
    `relationship_type_score` STRING COMMENT 'Numeric score (0–100) reflecting the nature of the relationship between the worker and the engaging party, per the IRS Common Law Test. Considers written contracts, employee benefits, permanency of relationship, and integral business activity.',
    `reviewing_officer_name` STRING COMMENT 'Full name of the compliance officer, HR attorney, or legal counsel who reviewed and approved this classification determination. Required for audit trail and regulatory defense.',
    `reviewing_officer_title` STRING COMMENT 'Job title or role of the individual who reviewed and approved the classification determination (e.g., Chief Compliance Officer, Employment Attorney, HR Director).',
    `source_system` STRING COMMENT 'The operational system of record from which this classification determination originated or was last updated. Supports data lineage and reconciliation across Bullhorn ATS/CRM, SAP SuccessFactors, TempWorks Payroll, Beeline VMS, or manual entry.. Valid values are `Bullhorn|SAP_SuccessFactors|TempWorks|Beeline_VMS|Manual`',
    `ss8_determination_result` STRING COMMENT 'The IRSs official determination result from Form SS-8 review. Employee = IRS determined worker is an employee; Independent Contractor = IRS confirmed IC status; Pending = IRS review in progress; Withdrawn = SS-8 filing was withdrawn.. Valid values are `employee|independent_contractor|pending|withdrawn`',
    `ss8_filed` BOOLEAN COMMENT 'Indicates whether IRS Form SS-8 (Determination of Worker Status for Purposes of Federal Employment Taxes and Income Tax Withholding) has been filed for this worker engagement. True = SS-8 filed with IRS; False = not filed.',
    `ss8_filed_date` DATE COMMENT 'Date on which IRS Form SS-8 was filed with the IRS for this worker engagement. Null if ss8_filed is False.',
    `updated_timestamp` TIMESTAMP COMMENT 'Timestamp when this worker classification record was most recently modified. Audit trail field required for DOL, IRS, and SOC 2 compliance. Tracks reclassification events and override changes.',
    `voluntary_classification_settlement` BOOLEAN COMMENT 'Indicates whether the staffing firm has enrolled this worker classification under the IRS Voluntary Classification Settlement Program (VCSP), which allows prospective reclassification of workers as employees with reduced tax liability.',
    `workers_comp_exempt` BOOLEAN COMMENT 'Indicates whether the worker is exempt from Workers Compensation coverage based on their classification (e.g., 1099 IC workers are typically exempt). Drives payroll and insurance configuration in TempWorks Payroll.',
    CONSTRAINT pk_worker_classification PRIMARY KEY(`worker_classification_id`)
) COMMENT 'Master record capturing FLSA worker classification determinations for each worker engagement — W-2 employee vs. 1099 independent contractor (IC). Stores classification type, determination basis (behavioral control, financial control, relationship type per IRS common law test), classification date, reviewing attorney or compliance officer, client-requested classification, override flags, co-employment risk rating, and IRS audit exposure notes. SSOT for IC vs. W-2 classification decisions.';

CREATE OR REPLACE TABLE `staffing_hr_ecm_v1`.`compliance`.`eeoc_filing` (
    `eeoc_filing_id` BIGINT COMMENT 'Unique surrogate identifier for each EEOC regulatory filing record in the Staffing Hr compliance system. Primary key for this transactional entity. Role: TRANSACTION_HEADER.',
    `amended_filing_eeoc_filing_id` BIGINT COMMENT 'Reference to the original EEOC filing record that this amendment supersedes. Populated only when is_amendment is True, enabling amendment history tracking.',
    `client_account_id` BIGINT COMMENT 'Foreign key linking to client.client_account. Business justification: EEO-1 filings are submitted per employer entity. In co-employment staffing arrangements, the client account is the reporting establishment. Compliance teams must link each EEOC filing to the client ac',
    `msa_id` BIGINT COMMENT 'Foreign key linking to contract.msa. Business justification: MSAs with federal contractors include EEOC/OFCCP compliance obligations. Real business need: MSA-driven filing requirements for federal contractor clients, linking filings to contractual obligations.',
    `job_category_id` BIGINT COMMENT 'Foreign key linking to joborder.job_category. Business justification: EEO-1 Component 1 filings require headcount breakdowns by EEO-1 job category. Linking eeoc_filing to the authoritative job_category record enables regulatory reporting by pulling order/placement data ',
    `location_id` BIGINT COMMENT 'Foreign key linking to client.location. Business justification: EEOC multi-establishment reporting requires each filing row to reference a specific client worksite. Staffing firms filing EEO-1 Component 1 for co-employed workers at client locations must link filin',
    `managed_program_id` BIGINT COMMENT 'Foreign key linking to client.managed_program. Business justification: MSP/EOR managed programs are distinct employer-of-record arrangements requiring separate EEOC filings. Compliance teams track EEO-1 submissions by managed program to fulfill program-level federal cont',
    `supplier_id` BIGINT COMMENT 'Foreign key linking to vendor.supplier. Business justification: EEO-1 filings in staffing are submitted by the staffing supplier as employer of record. Linking eeoc_filing to the supplier entity enables supplier-level OFCCP/EEOC regulatory reporting, diversity aud',
    `accepted_date` DATE COMMENT 'Date on which the EEOC officially accepted and validated this filing submission. Populated when filing_status transitions to accepted. Key date for audit readiness and compliance records.',
    `certifying_official_title` STRING COMMENT 'Job title of the company official who certified the EEOC filing. Typically a senior HR, legal, or executive officer with authority to attest to workforce data accuracy.',
    `confirmation_number` STRING COMMENT 'Official confirmation number issued by the EEOC upon successful receipt and acceptance of the filing submission. Used for audit readiness and correspondence with the EEOC.',
    `count_american_indian_alaska_native` STRING COMMENT 'Total number of employees self-identified as American Indian or Alaska Native (not Hispanic or Latino) across all job categories in this filing. One of the seven EEOC-mandated race/ethnicity categories.',
    `count_asian` STRING COMMENT 'Total number of employees self-identified as Asian (not Hispanic or Latino) across all job categories in this filing. One of the seven EEOC-mandated race/ethnicity categories.',
    `count_black_african_american` STRING COMMENT 'Total number of employees self-identified as Black or African American (not Hispanic or Latino) across all job categories in this filing. One of the seven EEOC-mandated race/ethnicity categories.',
    `count_hispanic_latino` STRING COMMENT 'Total number of employees self-identified as Hispanic or Latino across all job categories in this filing. One of the seven EEOC-mandated race/ethnicity categories.',
    `count_native_hawaiian_pacific_islander` STRING COMMENT 'Total number of employees self-identified as Native Hawaiian or Other Pacific Islander (not Hispanic or Latino) across all job categories in this filing. One of the seven EEOC-mandated race/ethnicity categories.',
    `count_two_or_more_races` STRING COMMENT 'Total number of employees self-identified as Two or More Races (not Hispanic or Latino) across all job categories in this filing. One of the seven EEOC-mandated race/ethnicity categories.',
    `count_white_non_hispanic` STRING COMMENT 'Total number of employees self-identified as White (not Hispanic or Latino) across all job categories in this filing. One of the seven EEOC-mandated race/ethnicity categories.',
    `created_timestamp` TIMESTAMP COMMENT 'Timestamp when this EEOC filing record was first created in the compliance system. Serves as the RECORD_AUDIT_CREATED audit field.',
    `data_source_system` STRING COMMENT 'Operational system of record from which the workforce headcount and demographic data was extracted to populate this EEOC filing. Supports data lineage and audit trail requirements.. Valid values are `SAP SuccessFactors|Bullhorn ATS|Kronos Workforce Ready|Manual Entry|Other`',
    `establishment_count` STRING COMMENT 'Total number of physical establishments (locations) included in this EEOC filing. Multi-establishment employers must report headcount data for each location.',
    `filing_deadline` DATE COMMENT 'Regulatory deadline date by which this EEOC filing must be submitted to remain in compliance. Set annually by the EEOC.',
    `filing_notes` STRING COMMENT 'Free-text notes or comments entered by the compliance team regarding this EEOC filing. May include explanations for data anomalies, amendment rationale, or internal review observations.',
    `filing_number` STRING COMMENT 'Externally-known unique reference number assigned to this EEOC filing submission, used for tracking and correspondence with the EEOC. Serves as the BUSINESS_IDENTIFIER for this transaction.',
    `filing_status` STRING COMMENT 'Current lifecycle state of the EEOC filing submission. Tracks progression from draft preparation through EEOC acceptance or rejection. Serves as the LIFECYCLE_STATUS for this transaction.. Valid values are `draft|submitted|accepted|rejected|amended|withdrawn`',
    `filing_year` STRING COMMENT 'Calendar year for which this EEOC report is being filed (e.g., 2023). Determines the applicable reporting period and regulatory deadline.',
    `is_amendment` BOOLEAN COMMENT 'Indicates whether this filing is an amendment to a previously submitted EEOC report. Amendments correct errors or update data in an accepted original filing.',
    `is_federal_contractor` BOOLEAN COMMENT 'Indicates whether the filing entity is a federal contractor or subcontractor subject to OFCCP regulations and Executive Order 11246, which imposes additional EEO obligations beyond standard EEOC requirements.',
    `is_first_time_filer` BOOLEAN COMMENT 'Indicates whether this is the first EEOC EEO-1 filing submitted by this employer. First-time filers may have different onboarding requirements and EEOC outreach procedures.',
    `ofccp_audit_flag` BOOLEAN COMMENT 'Indicates whether this EEOC filing has been flagged for or is subject to an OFCCP compliance audit or review. Enables proactive audit readiness tracking for federal contractor obligations.',
    `rejection_reason` STRING COMMENT 'Description of the reason provided by the EEOC for rejecting this filing submission. Populated only when filing_status is rejected. Used to guide corrective action and resubmission.',
    `report_component` STRING COMMENT 'Specifies the EEO-1 component being filed. Component 1 covers race/ethnicity and gender by job category; Component 2 (historically) covered pay data by race/ethnicity and gender. Relevant for EEO-1 filers.. Valid values are `Component 1|Component 2`',
    `report_type` STRING COMMENT 'Classification of the EEOC report form being filed. EEO-1 is the primary form for private employers and federal contractors; other types apply to unions, state/local governments, and educational institutions. Serves as the CLASSIFICATION_OR_TYPE for this transaction.. Valid values are `EEO-1|EEO-3|EEO-4|EEO-5|EEO-6`',
    `reporting_period_end` DATE COMMENT 'End date of the workforce data reporting period covered by this EEOC filing. Defines the close of the window from which the workforce snapshot is drawn.',
    `reporting_period_start` DATE COMMENT 'Start date of the workforce data reporting period covered by this EEOC filing. Defines the beginning of the window from which the workforce snapshot is drawn.',
    `snapshot_date` DATE COMMENT 'The specific pay period date used as the workforce count snapshot for the EEO-1 filing, typically a pay period in October through December of the filing year. Required by EEOC instructions.',
    `submission_method` STRING COMMENT 'Method used to submit the EEOC filing to the EEOC. Options include the EEOC online portal, bulk data upload, API integration, or legacy paper submission.. Valid values are `online_portal|bulk_upload|api|paper`',
    `submission_timestamp` TIMESTAMP COMMENT 'Date and time when the EEOC filing was officially submitted to the EEOC portal. Represents the principal real-world business event timestamp (BUSINESS_EVENT_TIMESTAMP) for this transaction.',
    `total_female_count` STRING COMMENT 'Total number of female employees across all job categories and establishments included in this EEOC filing. Required gender dimension for EEO-1 reporting.',
    `total_headcount` STRING COMMENT 'Total number of employees across all establishments included in this EEOC filing during the snapshot pay period. Represents the aggregate workforce count reported to the EEOC.',
    `total_male_count` STRING COMMENT 'Total number of male employees across all job categories and establishments included in this EEOC filing. Required gender dimension for EEO-1 reporting.',
    `updated_timestamp` TIMESTAMP COMMENT 'Timestamp when this EEOC filing record was last modified in the compliance system. Serves as the RECORD_AUDIT_UPDATED audit field.',
    CONSTRAINT pk_eeoc_filing PRIMARY KEY(`eeoc_filing_id`)
) COMMENT 'Transactional record for EEOC (Equal Employment Opportunity Commission) regulatory filings and reports submitted on behalf of the staffing firm or client. Covers EEO-1 Component 1 report submissions, filing period, establishment count, total headcount by race/ethnicity/gender/job category, submission confirmation number, filing status, and amendment history. Supports EEOC and OFCCP audit readiness.';

CREATE OR REPLACE TABLE `staffing_hr_ecm_v1`.`compliance`.`osha_incident` (
    `osha_incident_id` BIGINT COMMENT 'Unique system-generated identifier for each OSHA recordable workplace safety incident record. Primary key for this entity. TRANSACTION_HEADER role — represents a discrete workplace safety event with its own lifecycle.',
    `assignment_id` BIGINT COMMENT 'Reference to the active placement or assignment record under which the worker was deployed at the client site at the time of the incident. Establishes the staffing assignment context for co-employment liability determination.',
    `client_account_id` BIGINT COMMENT 'Reference to the client account (employer of record for the worksite) where the incident occurred. Used for client-level OSHA reporting, SLA compliance, and co-employment risk tracking.',
    `msa_id` BIGINT COMMENT 'Foreign key linking to contract.msa. Business justification: MSAs define safety standards, incident reporting obligations, and liability allocation. Real business need: MSA terms govern incident handling, client notification requirements, and liability determin',
    `ic_agreement_id` BIGINT COMMENT 'Foreign key linking to contract.ic_agreement. Business justification: When an IC worker suffers a workplace incident, the ic_agreement governs indemnification scope, workers comp obligations, and liability. Staffing HR must determine OSHA recordability and financial li',
    `location_id` BIGINT COMMENT 'Foreign key linking to client.location. Business justification: OSHA incidents occur at specific client worksites; OSHA 300 logs are establishment-specific. Normalizing client_site_location text to location_id FK enables accurate incident rollup, site safety metri',
    `managed_program_id` BIGINT COMMENT 'Foreign key linking to client.managed_program. Business justification: MSP managed programs track OSHA recordable incident rates as a program-level safety KPI reported in QBRs. Linking osha_incident to managed_program enables program-level OSHA 300 log aggregation, TRIR/',
    `offboarding_record_id` BIGINT COMMENT 'Foreign key linking to timesheet.offboarding_record. Business justification: When workplace injuries occur near separation date, linking incident to offboarding record captures workers comp claim continuity, return-to-work vs separation decisions, and rehire eligibility impact',
    `profile_id` BIGINT COMMENT 'Reference to the contingent worker (temporary employee or contractor) who was involved in the workplace safety incident. Links to the worker/candidate master record in the staffing system.',
    `regulatory_violation_id` BIGINT COMMENT 'Foreign key linking to compliance.regulatory_violation. Business justification: When an OSHA incident results in a citation or regulatory violation, this FK links to the regulatory_violation record. This normalizes osha_citation_number which can be retrieved via JOIN to regulator',
    `credential_instance_id` BIGINT COMMENT 'Foreign key linking to credentialing.credential_instance. Business justification: OSHA incident investigations review whether worker held required safety credentials (OSHA 10/30, forklift cert, etc.) at time of incident. Business process: Root cause analysis validates credential st',
    `sow_id` BIGINT COMMENT 'Foreign key linking to contract.sow. Business justification: SOW-specific worksites may have unique safety requirements. Real business need: SOW-level incident tracking for client-specific safety reporting and liability management.',
    `supplier_id` BIGINT COMMENT 'Foreign key linking to vendor.supplier. Business justification: OSHA incident investigations may involve third-party safety consultants, industrial hygienists, or expert witnesses. Track supplier for cost recovery from client/carrier, vendor quality assessment, an',
    `training_record_id` BIGINT COMMENT 'Foreign key linking to credentialing.training_record. Business justification: OSHA incident root cause investigations examine whether required safety training was completed and current. Linking osha_incident to the relevant training_record enables safety compliance managers to ',
    `vendor_agreement_id` BIGINT COMMENT 'Foreign key linking to contract.vendor_agreement. Business justification: Vendor_agreement defines workers_comp_minimum_usd and indemnification_scope for supplier-provided workers. When a vendor-supplied worker has an OSHA incident, the vendor_agreement governs liability al',
    `work_location_id` BIGINT COMMENT 'Foreign key linking to placement.work_location. Business justification: OSHA 300 log entries are tied to specific work locations (establishments). Staffing firms track incidents by placement work_location for their own OSHA recordkeeping and safety program management. osh',
    `body_part_affected` STRING COMMENT 'The specific body part injured or affected by the illness (e.g., lower back, right hand, left knee, eye, head). Required for OSHA Form 301 and used for ergonomic risk analysis and workers comp claim management. [ENUM-REF-CANDIDATE: head|neck|back|shoulder|arm|hand|finger|leg|knee|foot|eye|multiple — promote to reference product]',
    `corrective_action` STRING COMMENT 'Narrative description of the corrective and preventive actions taken or planned in response to the incident (e.g., retraining, equipment repair, process change, PPE provision, worksite modification). Required for OSHA compliance program documentation and client safety reporting.',
    `corrective_action_completed_date` DATE COMMENT 'The actual date on which all corrective and preventive actions were fully implemented and verified. Used to close the incident record and confirm compliance with the corrective action plan.',
    `corrective_action_due_date` DATE COMMENT 'The target completion date by which all corrective and preventive actions identified in the incident investigation must be implemented. Used for compliance tracking and client safety SLA management.',
    `created_timestamp` TIMESTAMP COMMENT 'The timestamp when this OSHA incident record was first created in the system. Serves as the RECORD_AUDIT_CREATED field for audit trail and data lineage purposes.',
    `days_away_from_work` STRING COMMENT 'The number of calendar days the worker was unable to work due to the injury or illness, as counted per OSHA recordkeeping rules (capped at 180 days for OSHA 300 log purposes). Required for OSHA 300 log Column K and DART rate calculation.',
    `days_restricted_duty` STRING COMMENT 'The number of calendar days the worker was placed on restricted work activity or job transfer due to the injury or illness, as counted per OSHA recordkeeping rules (capped at 180 days). Required for OSHA 300 log Column L and DART rate calculation.',
    `event_type` STRING COMMENT 'The type of event or exposure that directly produced the injury or illness, per BLS Occupational Injury and Illness Classification Manual (OIICS) event categories. Used for trend analysis, root cause classification, and OSHA 300A summary reporting. [ENUM-REF-CANDIDATE: fall|struck_by|caught_in|overexertion|exposure|transportation|violence|other — 8 candidates stripped; promote to reference product]',
    `incident_date` DATE COMMENT 'The calendar date on which the workplace injury or illness event occurred. This is the principal real-world event date used for OSHA 300 log entry, workers comp filing deadlines, and annual 300A summary reporting. Serves as the BUSINESS_EVENT_TIMESTAMP (date precision) for this transaction.',
    `incident_description` STRING COMMENT 'Narrative description of how the injury or illness occurred, including the sequence of events, equipment involved, and environmental conditions. Required for OSHA Form 301 and used for root cause analysis and corrective action planning.',
    `incident_number` STRING COMMENT 'Externally-known, human-readable business identifier for the incident (e.g., INC-2024-000123). Used in OSHA 300 log entries, workers comp filings, client communications, and regulatory correspondence. Serves as the BUSINESS_IDENTIFIER for this transaction.. Valid values are `^INC-[0-9]{4}-[0-9]{6}$`',
    `incident_status` STRING COMMENT 'Current lifecycle state of the OSHA incident record. open indicates active investigation; under_review indicates pending recordability determination; closed indicates fully resolved with corrective actions documented; appealed indicates contested recordability; voided indicates duplicate or erroneous entry.. Valid values are `open|under_review|closed|appealed|voided`',
    `incident_time` TIMESTAMP COMMENT 'The time of day (HH:MM, 24-hour format) at which the workplace incident occurred. Used for shift-pattern analysis, root cause investigation, and OSHA 300 log documentation.',
    `injury_illness_type` STRING COMMENT 'OSHA-defined classification of the nature of the workplace injury or illness. Maps directly to the OSHA Form 300 column headers: injury, skin disorder, respiratory condition, poisoning, hearing loss, or all other illness. Required for OSHA 300 log and 300A annual summary.. Valid values are `injury|skin_disorder|respiratory_condition|poisoning|hearing_loss|all_other_illness`',
    `injury_nature` STRING COMMENT 'Detailed description of the specific nature of the injury or illness (e.g., laceration, fracture, sprain, burn, contusion, amputation, concussion). Provides granularity beyond the OSHA Form 300 type classification for root cause analysis and trend reporting. [ENUM-REF-CANDIDATE: laceration|fracture|sprain|strain|burn|contusion|amputation|concussion|puncture|abrasion|dislocation|crush_injury — promote to reference product]',
    `investigation_completed_date` DATE COMMENT 'The date on which the formal incident investigation was completed and the investigation report was finalized. Used to track investigation timeliness and ensure compliance with internal safety program SLAs.',
    `is_fatality` BOOLEAN COMMENT 'Indicates whether the incident resulted in the death of the worker. True = fatality. Triggers mandatory OSHA reporting within 8 hours of employer knowledge under 29 CFR Part 1904.39 and activates escalation protocols.',
    `is_hospitalized` BOOLEAN COMMENT 'Indicates whether the worker was admitted to a hospital (inpatient) as a result of the incident. True = inpatient hospitalization. Triggers mandatory OSHA reporting within 24 hours under 29 CFR Part 1904.39.',
    `is_osha_recordable` BOOLEAN COMMENT 'Indicates whether the incident meets OSHA recordability criteria under 29 CFR Part 1904.7 (i.e., results in days away from work, restricted duty, medical treatment beyond first aid, loss of consciousness, or diagnosis of a significant injury/illness). True = recordable; False = first-aid only. Drives OSHA 300 log entry requirement.',
    `is_privacy_case` BOOLEAN COMMENT 'Indicates whether this incident qualifies as a privacy case under OSHA recordkeeping rules (e.g., sexual assault, mental illness, HIV/AIDS, needlestick, tuberculosis). True = privacy case. When true, the workers name must be withheld from the OSHA 300 log and replaced with privacy case.',
    `ita_submission_reference` STRING COMMENT 'The confirmation identifier returned by OSHAs Injury Tracking Application (ITA) upon electronic submission of the OSHA 300A annual summary data. Required for establishments with 250+ employees or in high-hazard industries under the OSHA Electronic Recordkeeping Rule.',
    `naics_code` STRING COMMENT 'The six-digit NAICS code for the client establishment where the incident occurred. Required for OSHA 300A annual summary and OSHA electronic submission (ITA/OSHA Data Collection) to classify the industry for benchmarking incidence rates.. Valid values are `^[0-9]{6}$`',
    `osha_300_log_entry_number` STRING COMMENT 'The sequential entry number assigned to this incident on the OSHA Form 300 (Log of Work-Related Injuries and Illnesses) for the applicable calendar year. Required for OSHA 300A annual summary reconciliation and regulatory audit. Null if incident is not recordable.',
    `osha_300_log_year` STRING COMMENT 'The calendar year of the OSHA Form 300 log in which this incident is recorded. Used to partition OSHA 300A annual summary reporting and multi-year trend analysis.',
    `osha_report_submitted` BOOLEAN COMMENT 'Indicates whether the required OSHA severe injury report (fatality, amputation, loss of eye, or inpatient hospitalization) has been submitted to OSHA within the mandated timeframe (8 hours for fatalities, 24 hours for other severe injuries).',
    `osha_report_submitted_timestamp` TIMESTAMP COMMENT 'The exact date and time at which the OSHA severe injury report was submitted to OSHA (via phone or online). Used to verify compliance with the 8-hour (fatality) and 24-hour (severe injury) reporting deadlines under 29 CFR Part 1904.39.',
    `outcome_type` STRING COMMENT 'The most severe outcome classification of the incident per OSHA recordkeeping hierarchy: fatality, days away from work, restricted duty or job transfer, medical treatment beyond first aid, or first aid only. Maps to OSHA Form 300 columns G through J. Drives recordability and severity classification.. Valid values are `days_away|restricted_duty|job_transfer|medical_treatment|first_aid_only|fatality`',
    `recordability_determination_date` DATE COMMENT 'The date on which the safety officer or compliance team made the final determination of whether the incident is OSHA recordable. Required for audit trail and to ensure timely OSHA 300 log entry within the 7-calendar-day requirement.',
    `reported_date` DATE COMMENT 'The date on which the incident was formally reported to the staffing agency or client safety officer. Used to measure reporting lag compliance against OSHA 24-hour and 8-hour reporting requirements for severe injuries.',
    `return_to_work_date` DATE COMMENT 'The date on which the injured worker returned to full or modified duty following the incident. Used to calculate actual days away from work, manage assignment continuity, and track workers comp claim closure.',
    `root_cause` STRING COMMENT 'Narrative or structured description of the underlying root cause(s) identified through incident investigation (e.g., inadequate training, equipment failure, unsafe work practice, environmental hazard, lack of PPE). Required for corrective action planning and OSHA compliance program documentation.',
    `root_cause_category` STRING COMMENT 'Standardized categorical classification of the primary root cause of the incident. Enables structured trend analysis and corrective action program tracking across the contingent workforce portfolio. [ENUM-REF-CANDIDATE: human_error|equipment_failure|environmental|process_deficiency|training_gap|ppe_failure|other — 7 candidates stripped; promote to reference product]',
    `updated_timestamp` TIMESTAMP COMMENT 'The timestamp when this OSHA incident record was last modified. Serves as the RECORD_AUDIT_UPDATED field for audit trail, change tracking, and data lineage purposes.',
    `worker_job_title` STRING COMMENT 'The job title or occupation of the contingent worker at the time of the incident. Required for OSHA Form 301 and used for occupation-level risk analysis and EEOC/OFCCP workforce safety reporting.',
    `worker_tenure_days` STRING COMMENT 'The number of days the worker had been on the current assignment at the client site at the time of the incident. Used for new-worker safety risk analysis, as OSHA data consistently shows elevated injury rates in the first 90 days of an assignment.',
    CONSTRAINT pk_osha_incident PRIMARY KEY(`osha_incident_id`)
) COMMENT 'Transactional record for OSHA recordable workplace safety incidents involving contingent workers on client sites. Captures incident date, client site location, injury/illness type, body part affected, OSHA recordability determination (recordable vs. first-aid only), days away from work, restricted duty days, OSHA 300 log entry number, workers compensation claim linkage, root cause, and corrective action taken. Supports OSHA 300/300A annual summary reporting.';

CREATE OR REPLACE TABLE `staffing_hr_ecm_v1`.`compliance`.`regulatory_violation` (
    `regulatory_violation_id` BIGINT COMMENT 'Unique system-generated identifier for each regulatory violation record. Primary key for the regulatory_violation data product. Serves as the SSOT reference for all compliance incident tracking across DOL, EEOC, OSHA, IRS, FCRA, GDPR, CCPA, and state labor board frameworks.',
    `assignment_id` BIGINT COMMENT 'Reference to the specific placement or assignment record associated with this violation. Links the violation to the active job assignment context, enabling placement-level compliance risk analysis and FLSA worker classification audits.',
    `audit_id` BIGINT COMMENT 'Foreign key linking to compliance.compliance_audit. Business justification: Regulatory violations can be discovered during compliance audits. When discovery_method = audit, this FK links to the specific audit that discovered the violation. Clear 1:N relationship - one viola',
    `client_account_id` BIGINT COMMENT 'Reference to the client account associated with this regulatory violation. Relevant for co-employment risk, joint employment determinations, client-site OSHA violations, and MSP/VMS program compliance breaches. Nullable when violation is internal to the staffing firm.',
    `msa_id` BIGINT COMMENT 'Foreign key linking to contract.msa. Business justification: Violations (wage-hour, misclassification) often breach MSA compliance clauses. Real business need: MSA breach tracking for client notification, liability allocation, and contractual remedy determinati',
    `credential_requirement_id` BIGINT COMMENT 'Foreign key linking to credentialing.credential_requirement. Business justification: Regulatory violations (unlicensed placement, missing drug screen, expired credential) are directly caused by unmet credential requirements. Linking violation to the specific credential_requirement tha',
    `i9_verification_id` BIGINT COMMENT 'Foreign key linking to compliance.i9_verification. Business justification: A regulatory violation may be directly tied to a specific I-9 verification failure (e.g., improper document acceptance, late completion, reverification lapse). The regulatory_violation table already h',
    `ic_agreement_id` BIGINT COMMENT 'Foreign key linking to contract.ic_agreement. Business justification: Worker misclassification and co-employment regulatory violations are directly tied to specific IC agreements. DOL/IRS enforcement actions require examining the ic_agreements worker_classification_bas',
    `location_id` BIGINT COMMENT 'Foreign key linking to client.location. Business justification: Many violations (wage/hour, safety, posting requirements) are site-specific. Location_id FK enables site-level violation tracking, remediation coordination with client site contacts, and jurisdiction-',
    `managed_program_id` BIGINT COMMENT 'Foreign key linking to client.managed_program. Business justification: Regulatory violations within MSP managed programs must be tracked at the program level for program governance, client reporting, and corrective action plan management. Program-level violation dashboar',
    `onboarding_engagement_id` BIGINT COMMENT 'Foreign key linking to recruitment.onboarding_engagement. Business justification: When violations are discovered during onboarding (failed background check disclosure, credential fraud, I-9 documentation issue), linking to onboarding record provides audit trail for remediation acti',
    `order_header_id` BIGINT COMMENT 'Foreign key linking to joborder.order_header. Business justification: Regulatory violations (prevailing wage, worker misclassification, I-9 failures) are often traceable to a specific job order that specified illegal terms. Compliance auditors must identify which orders',
    `prior_violation_regulatory_violation_id` BIGINT COMMENT 'Reference to the earlier regulatory_violation record that this violation is a recurrence of. Enables lineage tracking of repeat violations and supports OSHA repeat citation defense documentation. Nullable when repeat_violation_flag is false.',
    `profile_id` BIGINT COMMENT 'Reference to the primary worker (candidate, temporary associate, or placed employee) affected by or associated with this regulatory violation. Supports EEOC, FLSA, I-9, and OSHA compliance tracking at the individual worker level. Nullable when violation is organizational rather than worker-specific.',
    `sow_id` BIGINT COMMENT 'Foreign key linking to contract.sow. Business justification: SOW-specific violations (e.g., prevailing wage non-compliance on federal SOW). Real business need: SOW-level violation tracking for engagement-specific remediation and client reporting.',
    `state_compliance_rule_id` BIGINT COMMENT 'Foreign key linking to compliance.state_compliance_rule. Business justification: When a regulatory violation is of a state-specific rule, this FK links to the specific state compliance rule violated. This creates a 1:N relationship where one state rule can be violated multiple tim',
    `supplier_id` BIGINT COMMENT 'Foreign key linking to vendor.supplier. Business justification: Regulatory violations often require external legal counsel, remediation consultants, or audit firms for response and corrective action. Track supplier for cost recovery, vendor performance on resoluti',
    `vendor_agreement_id` BIGINT COMMENT 'Foreign key linking to contract.vendor_agreement. Business justification: Regulatory violations involving vendor-supplied workers (wage theft, safety violations, misclassification) trigger indemnification claims under the vendor_agreement. Staffing compliance teams must ref',
    `affected_client_count` STRING COMMENT 'Number of client accounts impacted by this regulatory violation. Relevant for systemic violations spanning multiple client engagements (e.g., widespread I-9 non-compliance, multi-site OSHA violations). Supports enterprise-wide compliance risk assessment.',
    `affected_worker_count` STRING COMMENT 'Number of workers (temporary associates, contractors, or permanent employees) impacted by this regulatory violation. Used for severity assessment, penalty calculation, and EEOC/DOL class-action risk evaluation. Supports board-level compliance reporting.',
    `agency_case_number` STRING COMMENT 'External case or docket number assigned by the regulatory agency (e.g., EEOC charge number, OSHA inspection number, DOL case reference, IRS audit ID). Required for tracking formal enforcement actions and agency correspondence. Nullable for internally-discovered violations not yet reported to an agency.',
    `agency_notification_date` DATE COMMENT 'Date on which the regulatory agency was formally notified of the violation or initiated contact with the organization. Triggers mandatory response timelines under OSHA, EEOC, and GDPR breach notification requirements. Nullable for violations not yet reported to an agency.',
    `applicable_statute` STRING COMMENT 'The specific federal, state, or local statute, regulation, or code section that was violated (e.g., 29 CFR Part 1904, FLSA Section 13(a)(1), Title VII of the Civil Rights Act, INA Section 274A, FCRA Section 604). Supports precise legal tracking and regulatory reporting.',
    `board_notification_date` DATE COMMENT 'Date on which the board of directors or executive leadership was formally notified of this regulatory violation. Nullable when board_notification_required is false or notification has not yet occurred. Supports governance audit trails.',
    `board_notification_required` BOOLEAN COMMENT 'Indicates whether this violation meets the threshold requiring notification to the board of directors or executive leadership. Typically triggered by critical severity, significant financial penalty, or class-action exposure. Supports board-level compliance reporting cadence.',
    `co_employment_risk_flag` BOOLEAN COMMENT 'Indicates whether this violation involves or creates co-employment or joint employment risk between the staffing firm and the client. Triggers enhanced legal review and client notification protocols. Critical for MSP/VMS program compliance and liability management.',
    `created_timestamp` TIMESTAMP COMMENT 'Timestamp when the regulatory violation record was first created in the compliance system. Supports audit trail requirements mandated by DOL, OSHA, and IRS regulatory frameworks. Distinct from discovery_date which reflects the real-world event time.',
    `data_privacy_breach_flag` BOOLEAN COMMENT 'Indicates whether this violation constitutes or involves a personal data breach requiring notification under GDPR Article 33, CCPA, or FCRA. Triggers the 72-hour GDPR breach notification clock and state-specific breach notification timelines.',
    `discovery_date` DATE COMMENT 'The calendar date on which the regulatory violation was first identified or discovered. Serves as the principal business event date for the violation record. Critical for calculating regulatory response deadlines, statute of limitations tracking, and trending analysis.',
    `discovery_method` STRING COMMENT 'The mechanism by which the regulatory violation was identified: internal audit, external complaint, agency notice, whistleblower report, client notification, or self-assessment. Critical for root cause analysis and improving proactive compliance controls.. Valid values are `internal_audit|external_complaint|agency_notice|whistleblower|client_notification|self_assessment`',
    `eeoc_charge_basis` STRING COMMENT 'The protected class or basis for an EEOC discrimination charge associated with this violation (e.g., race, color, sex, national origin, religion, age, disability, genetic information). Nullable for non-EEOC violations. [ENUM-REF-CANDIDATE: race|color|sex|national_origin|religion|age|disability|genetic_information|retaliation|other — promote to reference product]',
    `financial_penalty_amount` DECIMAL(18,2) COMMENT 'Monetary value of fines, penalties, or settlements assessed or anticipated as a result of this regulatory violation, expressed in USD. Includes OSHA citations, DOL back-pay orders, EEOC settlements, and IRS tax penalties. Supports financial risk reporting and board-level compliance dashboards.',
    `i9_everify_flag` BOOLEAN COMMENT 'Indicates whether this violation specifically involves I-9 Employment Eligibility Verification or E-Verify non-compliance under the Immigration and Nationality Act. Triggers mandatory ICE/DHS reporting protocols and I-9 audit remediation workflows.',
    `jurisdiction_country` STRING COMMENT 'ISO 3166-1 alpha-3 country code for the jurisdiction in which the violation occurred (e.g., USA, GBR, CAN). Supports international compliance tracking under GDPR and other cross-border regulatory frameworks for staffing firms with global operations.. Valid values are `^[A-Z]{3}$`',
    `jurisdiction_state` STRING COMMENT 'Two-letter U.S. state code (or equivalent jurisdiction identifier) where the violation occurred or where the applicable law is enforced. Supports state labor board reporting, state-specific wage and hour compliance, and CCPA/state privacy law tracking.. Valid values are `^[A-Z]{2}$`',
    `legal_counsel_involved` BOOLEAN COMMENT 'Indicates whether internal or external legal counsel has been engaged in connection with this regulatory violation. Triggers attorney-client privilege protections and routes the record to the legal hold workflow. Required for board-level compliance reporting.',
    `notes` STRING COMMENT 'Free-text field for additional compliance officer notes, legal observations, or contextual information not captured in structured fields. Supports nuanced documentation of complex multi-framework violations and ongoing investigation details.',
    `ofccp_audit_flag` BOOLEAN COMMENT 'Indicates whether this violation is associated with an OFCCP compliance review or audit of federal contractor obligations. Triggers affirmative action plan review and OFCCP conciliation agreement workflows for federal contractor clients.',
    `osha_citation_type` STRING COMMENT 'OSHA-specific citation classification for safety violations: willful, serious, other-than-serious, repeat, or de minimis. Determines penalty calculation under OSHA 29 CFR Part 1903. Nullable for non-OSHA violations.. Valid values are `willful|serious|other_than_serious|repeat|de_minimis`',
    `penalty_currency_code` STRING COMMENT 'ISO 4217 three-letter currency code for the financial penalty amount (e.g., USD for U.S. Dollar, EUR for Euro). Supports international operations under GDPR and multi-jurisdiction compliance tracking.. Valid values are `^[A-Z]{3}$`',
    `regulatory_body` STRING COMMENT 'The governing regulatory authority or agency associated with this violation (e.g., DOL, EEOC, OSHA, OFCCP, IRS, FCRA, GDPR, CCPA, state labor board). Drives routing to appropriate legal counsel and determines mandatory response timelines. [ENUM-REF-CANDIDATE: DOL|EEOC|OSHA|OFCCP|IRS|FCRA|GDPR|CCPA|state_labor_board|other — promote to reference product]',
    `remediation_completed_date` DATE COMMENT 'Actual date on which the remediation plan was fully executed and the violation was resolved. Used to calculate remediation cycle time KPIs and to confirm closure eligibility. Nullable until remediation is complete.',
    `remediation_due_date` DATE COMMENT 'Target date by which the remediation plan must be fully executed and the violation resolved. Drives SLA tracking on the compliance dashboard and triggers escalation alerts when approaching or past due.',
    `remediation_plan` STRING COMMENT 'Detailed description of the corrective action plan developed to address and resolve the regulatory violation. Includes specific steps, process changes, training requirements, and system corrections required. Supports DOL, OSHA, and EEOC corrective action documentation requirements.',
    `repeat_violation_flag` BOOLEAN COMMENT 'Indicates whether this violation is a recurrence of a previously identified and remediated violation of the same type. Repeat violations carry significantly higher OSHA and DOL penalty multipliers and indicate systemic compliance control failures.',
    `resolution_status` STRING COMMENT 'Current lifecycle state of the regulatory violation record, tracking progress from initial identification through remediation and closure. Drives compliance dashboard KPIs and board-level reporting. [ENUM-REF-CANDIDATE: open|in_remediation|pending_review|resolved|closed|escalated — promote to reference product]. Valid values are `open|in_remediation|pending_review|resolved|closed|escalated`',
    `response_deadline_date` DATE COMMENT 'Mandatory deadline by which the organization must respond to the regulatory agency or complete required filings. Derived from agency notification date plus statutory response windows (e.g., OSHA 15-day informal conference, EEOC 180-day charge response). Critical for SLA compliance tracking.',
    `root_cause_category` STRING COMMENT 'High-level categorization of the underlying root cause driving the violation (e.g., process failure, training gap, system error, policy gap, vendor non-compliance, documentation failure, worker misclassification error). Supports systemic compliance improvement and regulatory risk trending. [ENUM-REF-CANDIDATE: process_failure|training_gap|system_error|policy_gap|vendor_noncompliance|documentation_failure|misclassification_error|other — promote to reference product]',
    `severity_level` STRING COMMENT 'Standardized severity classification of the regulatory violation: minor (low risk, administrative), moderate (process failure, correctable), major (significant regulatory exposure), critical (immediate legal/financial risk, board notification required). Drives escalation workflows and KPI dashboards.. Valid values are `minor|moderate|major|critical`',
    `source_system` STRING COMMENT 'The operational system of record from which this violation record originated or was first captured (e.g., Bullhorn ATS/CRM, SAP SuccessFactors, Sterling Background Check, DocuSign CLM, TempWorks Payroll, Kronos Workforce Ready, or manual entry by compliance team). Supports data lineage and Silver layer ingestion tracking. [ENUM-REF-CANDIDATE: bullhorn|sap_successfactors|sterling_bgc|docusign_clm|tempworks|kronos|manual_entry|other — 8 candidates stripped; promote to reference product]',
    `updated_timestamp` TIMESTAMP COMMENT 'Timestamp of the most recent modification to the regulatory violation record. Required for audit trail integrity and change tracking across the violation lifecycle. Supports SOC 2 Type II audit log requirements.',
    `violation_description` STRING COMMENT 'Detailed narrative description of the regulatory violation, including the specific non-compliant act or omission, the circumstances under which it occurred, and the regulatory requirement that was breached. Supports legal counsel review and regulatory agency correspondence.',
    `violation_number` STRING COMMENT 'Externally-known, human-readable business identifier for the violation record (e.g., RV-2024-000123). Used in correspondence with regulatory agencies, legal counsel, and board-level reporting. Sourced from the compliance management workflow.. Valid values are `^RV-[0-9]{4}-[0-9]{6}$`',
    `violation_type` STRING COMMENT 'Categorical classification of the regulatory violation by type (e.g., I-9 non-compliance, FLSA misclassification, EEOC discrimination, OSHA safety breach, FCRA background check violation, GDPR data breach, CCPA privacy violation, wage and hour violation, co-employment breach). [ENUM-REF-CANDIDATE: i9_noncompliance|flsa_misclassification|eeoc_discrimination|osha_safety|fcra_violation|gdpr_breach|ccpa_violation|wage_hour|co_employment|other — promote to reference product]',
    `worker_classification_type` STRING COMMENT 'The IRS/FLSA worker classification applicable to the affected worker at the time of the violation: W-2 (employee), 1099 (independent contractor), EOR (Employer of Record), PEO (Professional Employer Organization), FTE (Full-Time Equivalent), or contract-to-hire. Central to FLSA misclassification violation tracking and IRS audit defense.. Valid values are `W2|1099|EOR|PEO|FTE|contract_to_hire`',
    CONSTRAINT pk_regulatory_violation PRIMARY KEY(`regulatory_violation_id`)
) COMMENT 'Transactional record for identified regulatory violations, compliance breaches, and enforcement actions across all regulatory frameworks (DOL, EEOC, OSHA, IRS, FCRA, GDPR, CCPA, state labor boards). Captures violation type, regulatory body, applicable regulation/statute, discovery date, discovery method (internal audit, external complaint, agency notice, whistleblower report, client notification, self-assessment), severity level (minor/moderate/major/critical), affected worker or client count, root cause category, remediation plan, remediation owner, remediation due date, resolution status, financial penalty amount, legal counsel involvement flag, and board notification flag. SSOT for compliance incident tracking. Supports compliance dashboard KPIs, regulatory risk trending, and board-level compliance reporting.';

CREATE OR REPLACE TABLE `staffing_hr_ecm_v1`.`compliance`.`audit` (
    `audit_id` BIGINT COMMENT 'Unique surrogate identifier for each compliance audit record. Primary key for the compliance_audit data product. Entity role: TRANSACTION_HEADER — represents a discrete compliance audit event with a defined lifecycle from initiation through closure.',
    `client_account_id` BIGINT COMMENT 'Reference to the client account associated with this audit, if the audit is client-specific (e.g., a client compliance audit or VMS-driven audit). Null for enterprise-wide or regulatory audits not tied to a single client.',
    `msa_id` BIGINT COMMENT 'Foreign key linking to contract.msa. Business justification: Audits (OFCCP, DOL) scope MSA-covered engagements. Real business need: MSA defines audit scope, linking audit findings to contractual obligations for client reporting and remediation.',
    `credential_package_id` BIGINT COMMENT 'Foreign key linking to credentialing.credential_package. Business justification: Compliance audits (OFCCP, DOL, client audits) are scoped to specific credential packages used for a workforce program. Linking audit to credential_package enables auditors to pull all credential requi',
    `credential_requirement_id` BIGINT COMMENT 'Foreign key linking to credentialing.credential_requirement. Business justification: Compliance audits scoped to specific client credential requirements (e.g., license verification practices, drug screen panel compliance) reference the exact credential_requirement being audited. Enabl',
    `ic_agreement_id` BIGINT COMMENT 'Foreign key linking to contract.ic_agreement. Business justification: IRS SS-8 audits and DOL IC misclassification audits require examining specific IC agreements. The audits worker_classification_scope directly maps to ic_agreement terms. Staffing compliance teams mus',
    `location_id` BIGINT COMMENT 'Foreign key linking to client.location. Business justification: Compliance audits (OSHA site audits, wage-hour investigations, I-9 audits) are frequently scoped to a specific client worksite. Audit teams must link audits to the exact location for site-level correc',
    `managed_program_id` BIGINT COMMENT 'Foreign key linking to client.managed_program. Business justification: MSP/RPO program audits (supplier compliance, worker classification, SLA adherence) are common in staffing. Managed_program_id FK enables program-level audit scope definition, corrective action trackin',
    `requirement_id` BIGINT COMMENT 'Foreign key linking to compliance.requirement. Business justification: An audit is typically scoped to verify compliance against one or more specific regulatory requirements. Adding requirement_id to audit links each audit record to the primary governing requirement bein',
    `sow_id` BIGINT COMMENT 'Foreign key linking to contract.sow. Business justification: SOW-specific audits (e.g., federal contract compliance review). Real business need: SOW-level audit tracking for engagement-specific findings and remediation.',
    `state_compliance_rule_id` BIGINT COMMENT 'Foreign key linking to compliance.state_compliance_rule. Business justification: Audits are frequently triggered by or scoped to specific state and local jurisdiction compliance rules (e.g., California AB5, New York paid sick leave, Illinois IDOL requirements). Adding state_compli',
    `supplier_id` BIGINT COMMENT 'Foreign key linking to vendor.supplier. Business justification: Compliance audits are frequently conducted by external audit firms, legal counsel, or specialized compliance consultants. Track supplier for independence verification, cost management, vendor quality ',
    `vendor_agreement_id` BIGINT COMMENT 'Foreign key linking to contract.vendor_agreement. Business justification: OFCCP, DOL, and state audits of vendor/supplier compliance programs require examining the vendor_agreements background_check_standard, everify_required_flag, and drug_screen_required_flag. Audit scop',
    `actual_penalty_amount` DECIMAL(18,2) COMMENT 'Actual monetary penalty, fine, or back-wage settlement amount assessed as a result of the audit, expressed in USD. Populated upon audit closure when a regulatory determination or settlement has been reached. Distinct from estimated_financial_exposure.',
    `affected_population_size` STRING COMMENT 'Total number of workers, placements, timesheets, or records within the audit scope that were subject to review. Used to assess the breadth of compliance exposure and calculate error rates (e.g., I-9 deficiency rate per 100 workers).',
    `audit_number` STRING COMMENT 'Externally-known, human-readable business identifier for the audit (e.g., AUD-2024-000123). Used for cross-referencing with regulatory agencies, external auditors, and internal tracking systems. Sourced from the compliance management module.. Valid values are `^AUD-[0-9]{4}-[0-9]{6}$`',
    `audit_scope` STRING COMMENT 'Narrative description of the audit scope, including the business processes, organizational units, client accounts, placement types, or regulatory requirements under review. Defines the boundaries of the audit engagement.',
    `audit_source` STRING COMMENT 'Indicates whether the audit was initiated internally (by the compliance team), externally (by a regulatory agency or external auditor), at client request, or self-initiated as part of a proactive compliance program.. Valid values are `internal|external|regulatory|client_requested|self_initiated`',
    `audit_status` STRING COMMENT 'Current lifecycle state of the compliance audit. Tracks progression from planning through closure. Valid values: planned (scheduled but not started), in_progress (fieldwork underway), findings_issued (draft or final report delivered), remediation (corrective actions in progress), closed (all findings resolved and audit concluded), cancelled (audit voided before completion).. Valid values are `planned|in_progress|findings_issued|remediation|closed|cancelled`',
    `audit_type` STRING COMMENT 'Classification of the compliance audit by regulatory or operational domain. Indicates the primary subject matter of the audit. [ENUM-REF-CANDIDATE: i9_audit|payroll_tax_audit|flsa_audit|fcra_audit|soc2_audit|client_compliance_audit|dol_audit|osha_audit|eeoc_audit|ofccp_audit|workers_comp_audit|state_wage_audit — promote to reference product]',
    `closure_date` DATE COMMENT 'The date on which the audit was formally closed, meaning all findings have been remediated and accepted by the auditing party. Null if the audit is still open.',
    `corrective_action_plan_due_date` DATE COMMENT 'The deadline by which the formal Corrective Action Plan (CAP) must be submitted to the auditing party or regulatory agency. Drives remediation scheduling and escalation workflows.',
    `corrective_action_plan_status` STRING COMMENT 'Current status of the Corrective Action Plan (CAP) associated with this audit. Tracks whether a CAP is required, has been submitted, accepted by the auditing party, rejected, or is overdue.. Valid values are `not_required|pending|submitted|accepted|rejected|overdue`',
    `created_timestamp` TIMESTAMP COMMENT 'Timestamp when this compliance audit record was first created in the system. Represents the record audit trail creation point. Sourced from the compliance management platform or manual entry in the Silver layer.',
    `critical_findings_count` STRING COMMENT 'Number of findings rated as critical severity within this audit. Critical findings typically require immediate escalation and expedited remediation. Tracked separately for executive and regulatory reporting.',
    `estimated_financial_exposure` DECIMAL(18,2) COMMENT 'Estimated monetary exposure or liability associated with the audit findings, expressed in USD. Includes potential penalties, back wages, fines, or remediation costs. Used for financial risk management and executive reporting. Not a calculated aggregate — represents the compliance teams point-in-time risk estimate.',
    `external_auditor_firm` STRING COMMENT 'Name of the external auditing firm, regulatory agency, or third-party organization conducting the audit. Null for purely internal audits. Examples: KPMG, Deloitte, DOL Wage and Hour Division, EEOC field office.',
    `fieldwork_end_date` DATE COMMENT 'The date on which active audit fieldwork was completed. Marks the transition from evidence gathering to findings analysis and report drafting.',
    `fieldwork_start_date` DATE COMMENT 'The date on which active audit fieldwork (evidence collection, interviews, document review) commenced. Represents the principal real-world business event timestamp for the audit engagement start. Used for SLA and TTF (Time to Fill) compliance tracking.',
    `geographic_scope` STRING COMMENT 'Description of the geographic coverage of the audit, such as specific states, regions, or enterprise-wide. Relevant for state wage and hour audits (SUTA, state FLSA equivalents), CCPA (California), and multi-state compliance reviews.',
    `initiating_agency` STRING COMMENT 'Name of the regulatory agency, external auditing firm, or client organization that initiated or requested the audit. Examples: U.S. Department of Labor, EEOC, OSHA, IRS, client legal counsel, or an external CPA firm conducting a SOC 2 review.',
    `lead_auditor_name` STRING COMMENT 'Full name of the primary auditor responsible for conducting the audit. May be an internal compliance officer or an external auditor from a regulatory agency or third-party firm. Used for accountability and communication tracking.',
    `legal_counsel_engaged` BOOLEAN COMMENT 'Indicates whether external or internal legal counsel has been engaged in connection with this audit. True when legal representation is involved, which may affect document privilege and response strategy.',
    `methodology` STRING COMMENT 'The approach used to conduct the audit. Statistical sample audits review a representative subset; full population audits review all records; targeted sample focuses on high-risk records; desk review is document-only; on-site involves physical inspection; hybrid combines methods.. Valid values are `statistical_sample|full_population|targeted_sample|desk_review|on_site|hybrid`',
    `notes` STRING COMMENT 'Free-text field for compliance team notes, observations, or contextual information about the audit that does not fit structured fields. May include background on regulatory context, client relationship considerations, or escalation history.',
    `open_findings_count` STRING COMMENT 'Number of audit findings that remain open (not yet remediated or closed) at the time of record update. Supports real-time compliance dashboard monitoring and escalation tracking.',
    `overall_disposition` STRING COMMENT 'Final outcome or disposition of the audit. Indicates whether the organization passed, passed with findings requiring remediation, failed, or whether the audit was inconclusive or withdrawn. Key metric for executive compliance dashboards and regulatory reporting.. Valid values are `pass|pass_with_findings|fail|inconclusive|withdrawn`',
    `overall_risk_rating` STRING COMMENT 'Aggregate risk rating assigned to the audit based on the severity and volume of findings. Rolled up from individual finding risk ratings. Drives escalation protocols and executive reporting. Values: low, medium, high, critical.. Valid values are `low|medium|high|critical`',
    `period_end_date` DATE COMMENT 'The ending date of the time period under audit review. Defines the latest date of business activity or records subject to examination. Together with audit_period_start_date, establishes the audit window.',
    `period_start_date` DATE COMMENT 'The beginning date of the time period under audit review. Defines the earliest date of business activity or records subject to examination. Distinct from the audit execution start date.',
    `placement_type_scope` STRING COMMENT 'The type of worker placement covered by this audit. Indicates whether the audit applies to temporary workers, permanent placements, contract-to-hire (temp-to-perm), direct hire, SOW (Statement of Work) engagements, or all placement types. Relevant for FLSA worker classification and co-employment risk audits.. Valid values are `temporary|permanent|contract_to_hire|direct_hire|sow|all`',
    `prior_audit_reference` STRING COMMENT 'Audit number of the most recent prior audit of the same type, used to establish continuity and track repeat findings. Enables year-over-year compliance trend analysis without creating a hard FK dependency at this stage.',
    `privilege_hold_flag` BOOLEAN COMMENT 'Indicates whether attorney-client privilege or work product doctrine has been asserted over audit materials. When True, certain audit documents are restricted from disclosure. Relevant for regulatory audits where legal exposure exists.',
    `regulatory_citation` STRING COMMENT 'The primary federal or state regulatory citation, statute, or rule that is the subject of the audit. Examples: 29 CFR Part 516 (FLSA recordkeeping), 8 CFR 274a (I-9), 29 CFR 1904 (OSHA recordkeeping), IRC Section 3509 (worker misclassification). Supports regulatory mapping and citation-level trend analysis.',
    `regulatory_notice_reference` STRING COMMENT 'Official case number, docket number, or notice reference assigned by the regulatory agency initiating the audit. Examples: DOL case number, EEOC charge number, IRS examination reference. Used for official correspondence and regulatory tracking.',
    `repeat_finding_flag` BOOLEAN COMMENT 'Indicates whether this audit contains one or more findings that were also identified in a prior audit cycle (repeat findings). Repeat findings signal systemic control failures and typically result in elevated regulatory scrutiny and penalties.',
    `report_issued_date` DATE COMMENT 'The date on which the formal audit report (draft or final) was issued to stakeholders. Triggers the remediation clock for findings with regulatory deadlines.',
    `sample_size` STRING COMMENT 'Number of records, transactions, or workers included in the audit sample. Applicable when audit_methodology is statistical_sample or targeted_sample. Used to calculate deficiency rates and statistical confidence levels.',
    `subtype` STRING COMMENT 'Secondary classification providing additional specificity within the audit type. For example, within a payroll_tax_audit: FICA, FUTA, SUTA, or worker classification (W-2 vs 1099/IC). Enables granular reporting and trend analysis by compliance sub-domain.',
    `total_findings_count` STRING COMMENT 'Total number of audit findings identified during the audit engagement. Includes all severity levels. Used for KPI reporting and trend analysis across audit cycles.',
    `updated_timestamp` TIMESTAMP COMMENT 'Timestamp when this compliance audit record was last modified. Supports change tracking, data lineage, and audit trail requirements for the Silver layer lakehouse.',
    `worker_classification_scope` STRING COMMENT 'Indicates whether the audit covers W-2 employees, 1099 independent contractors (IC), both classifications, or is not applicable to worker classification. Critical for IRS worker misclassification audits and FLSA compliance reviews.. Valid values are `w2|1099|both|not_applicable`',
    CONSTRAINT pk_audit PRIMARY KEY(`audit_id`)
) COMMENT 'Master record for internal and external compliance audits conducted across the staffing firms operations, with embedded audit finding detail records. Covers audit type (I-9 audit, payroll tax audit, FLSA audit, FCRA audit, SOC 2 audit, client compliance audit, DOL audit), audit scope, auditor (internal team or external firm), audit period, and final audit disposition. Each audit contains one-to-many finding records capturing: finding category (documentation gap, process failure, regulatory breach, control weakness), regulatory citation, affected population size, risk rating (low/medium/high/critical), recommended corrective action, responsible owner, due date, remediation evidence, and closure status. SSOT for all compliance audit activity and finding lifecycle management from identification through closure. Distinct from ofccp_compliance which covers OFCCP-specific federal contractor reviews and Affirmative Action Plans.';

CREATE OR REPLACE TABLE `staffing_hr_ecm_v1`.`compliance`.`wage_hour_determination` (
    `wage_hour_determination_id` BIGINT COMMENT 'Unique system-generated identifier for each wage and hour compliance determination record. Primary key for this entity. TRANSACTION_HEADER role — covers FLSA overtime eligibility, prevailing wage, exempt/non-exempt classification, and pay equity assessments.',
    `client_account_id` BIGINT COMMENT 'Reference to the client account at whose worksite or under whose contract the worker is engaged. Client context may affect prevailing wage applicability, state-specific minimum wage, and co-employment risk.',
    `msa_id` BIGINT COMMENT 'Foreign key linking to contract.msa. Business justification: MSAs define pay rate approval processes, markup caps, and FLSA compliance obligations. Real business need: MSA terms govern wage determinations for contractual compliance and client approval.',
    `contract_rate_schedule_id` BIGINT COMMENT 'Foreign key linking to contract.contract_rate_schedule. Business justification: Wage determinations validate against contracted rate schedules. Real business need: rate compliance validation ensures pay rates align with MSA/SOW rate cards for audit defense.',
    `ic_agreement_id` BIGINT COMMENT 'Foreign key linking to contract.ic_agreement. Business justification: Wage/hour determinations for IC workers must reference the ic_agreements payment_rate, payment_structure, and worker_classification_basis. DOL FLSA compliance and prevailing wage analysis for ICs req',
    `location_id` BIGINT COMMENT 'Foreign key linking to client.location. Business justification: Prevailing wage (Davis-Bacon, SCA) and local minimum wage ordinances are location-specific (city/county level). Location_id FK provides precise jurisdiction for rate validation, compliance with local ',
    `managed_program_id` BIGINT COMMENT 'Foreign key linking to client.managed_program. Business justification: Prevailing wage and SCA wage determinations are often program-specific in government contract MSP arrangements. Linking wage_hour_determination to managed_program enables program-level wage compliance',
    `order_header_id` BIGINT COMMENT 'Reference to the job order or requisition associated with this determination. Provides the job classification context used to assess FLSA exemption status and applicable wage rates.',
    `position_requirement_id` BIGINT COMMENT 'Foreign key linking to joborder.position_requirement. Business justification: Wage and hour determinations (FLSA classification, prevailing wage, OT thresholds) are made at the position level. position_requirement holds pay_rate_min, pay_rate_max, employment_type, and worker_cl',
    `prior_determination_wage_hour_determination_id` BIGINT COMMENT 'Reference to the previous wage and hour determination record that this determination supersedes or replaces. Supports determination versioning and audit trail for changes in classification or pay rate over time.',
    `profile_id` BIGINT COMMENT 'Reference to the worker (candidate) subject to this wage and hour determination. Serves as the PARTY_REFERENCE for this transaction, linking to the individual whose classification and pay rate are being assessed.',
    `requirement_id` BIGINT COMMENT 'Foreign key linking to compliance.requirement. Business justification: A wage and hour determination is made in response to or governed by a specific compliance requirement (e.g., FLSA minimum wage, Davis-Bacon prevailing wage, state overtime rules). Adding requirement_i',
    `sow_id` BIGINT COMMENT 'Foreign key linking to contract.sow. Business justification: SOWs specify labor categories, bill rates, and prevailing wage requirements. Real business need: SOW-driven wage determination for engagement-specific rate validation and compliance.',
    `state_compliance_rule_id` BIGINT COMMENT 'Foreign key linking to compliance.state_compliance_rule. Business justification: Wage and hour determinations follow state-specific compliance rules (minimum wage, overtime rules vary by state). When applicable_law references state law, this FK links to the specific state rule. Cl',
    `supplier_id` BIGINT COMMENT 'Foreign key linking to vendor.supplier. Business justification: Wage/hour classifications (FLSA exemption, prevailing wage) often require external legal review or DOL compliance specialists. Track supplier for audit defense preparation, cost allocation to client/e',
    `vendor_agreement_id` BIGINT COMMENT 'Foreign key linking to contract.vendor_agreement. Business justification: Wage/hour determinations for vendor-supplied workers reference the vendor_agreements markup_cap_percentage and fee_schedule_type to validate pay equity and prevailing wage compliance. Staffing compli',
    `worker_classification_id` BIGINT COMMENT 'Foreign key linking to compliance.worker_classification. Business justification: Wage and hour determination references the worker classification determination. This normalizes the worker_classification field which can be retrieved via JOIN to worker_classification. Clear 1:N rela',
    `applicable_law` STRING COMMENT 'The primary federal or state law or regulation governing this determination (e.g., FLSA, Davis-Bacon Act, Service Contract Act, California Labor Code §510, New York Minimum Wage Order). Supports multi-jurisdiction compliance tracking.',
    `co_employment_risk_level` STRING COMMENT 'Assessed level of co-employment or joint employment risk for this worker engagement based on the degree of client control over the worker. High or critical risk may require EOR arrangement or contract restructuring to mitigate joint employer liability.. Valid values are `low|medium|high|critical`',
    `compliance_notes` STRING COMMENT 'Free-text field for compliance officer annotations, determination rationale, exceptions, or special circumstances relevant to this wage and hour determination. Supports DOL audit documentation and FLSA litigation defense narrative.',
    `created_timestamp` TIMESTAMP COMMENT 'Timestamp when this wage and hour determination record was first created in the system. Supports audit trail requirements for DOL, IRS, and SOC 2 Type II compliance.',
    `determination_date` DATE COMMENT 'The principal business event date on which the wage and hour determination was formally made. This is the operative date for compliance purposes, DOL audit readiness, and FLSA litigation defense — distinct from record creation timestamp.',
    `determination_number` STRING COMMENT 'Externally-known business identifier for this determination record, used in DOL audit correspondence, compliance officer sign-off documentation, and FLSA litigation defense filings. Format: WHD-YYYY-NNNNNN.',
    `determination_status` STRING COMMENT 'Current lifecycle state of the wage and hour determination record. draft indicates initial assessment in progress; pending_review awaits compliance officer sign-off; approved is finalized and operative; superseded replaced by a newer determination; appealed under formal challenge; closed no longer active.. Valid values are `draft|pending_review|approved|superseded|appealed|closed`',
    `dol_audit_flag` BOOLEAN COMMENT 'Indicates whether this determination record has been flagged as part of an active or anticipated DOL Wage and Hour Division audit. True triggers enhanced documentation retention and compliance officer review.',
    `dol_wage_determination_number` STRING COMMENT 'The official U.S. Department of Labor wage determination number (from SAM.gov or DOL Wage Determinations Online) applicable to this engagement under Davis-Bacon or Service Contract Act. Null if prevailing wage does not apply.',
    `dt_threshold_hours` DECIMAL(18,2) COMMENT 'The daily or weekly hour threshold beyond which double-time (DT) pay is required. Applicable in states such as California where hours over 12 in a day or over 8 on the 7th consecutive day trigger DT. Null if DT does not apply to this engagement.',
    `effective_end_date` DATE COMMENT 'Date on which this wage and hour determination expires or is superseded. Null indicates the determination remains in effect indefinitely. Used to manage determination versioning and ensure current applicability.',
    `effective_start_date` DATE COMMENT 'Date from which this wage and hour determination becomes operative for the worker engagement. Pay rates, overtime thresholds, and classification rules apply starting this date.',
    `exemption_basis` STRING COMMENT 'The specific FLSA white-collar or other exemption category applied when the worker is classified as exempt. none applies to non-exempt workers. Required for DOL audit documentation and FLSA litigation defense to demonstrate the basis for exemption. [ENUM-REF-CANDIDATE: executive|administrative|professional|computer_employee|outside_sales|highly_compensated|motor_carrier|none — 8 candidates stripped; promote to reference product]',
    `flsa_classification` STRING COMMENT 'FLSA overtime exemption classification for the worker. exempt workers are not entitled to overtime pay; non_exempt workers must receive 1.5x pay for hours over 40/week; highly_compensated_exempt meets the HCE threshold; partial_exempt applies to specific industry exemptions (e.g., motor carrier). Core field for FLSA litigation defense.. Valid values are `exempt|non_exempt|highly_compensated_exempt|partial_exempt`',
    `job_title` STRING COMMENT 'The job title of the worker at the time of this determination. Used to validate FLSA exemption basis (e.g., executive, professional), prevailing wage job classification, and pay equity peer group comparisons.',
    `litigation_hold_flag` BOOLEAN COMMENT 'Indicates whether this determination record is subject to a litigation hold due to active or threatened FLSA litigation. Records under litigation hold must not be modified or deleted.',
    `minimum_wage_applicable` DECIMAL(18,2) COMMENT 'The minimum wage rate (per hour, USD) applicable to this worker based on federal, state, or local law — whichever is highest. Used to validate that pay_rate_validated meets or exceeds the legal floor. Supports state-specific minimum wage compliance tracking.',
    `minimum_wage_jurisdiction` STRING COMMENT 'The jurisdiction (federal, state, or local municipality) whose minimum wage rate was applied as the floor for this determination. Examples: Federal, California, New York City. Supports multi-jurisdiction compliance reporting.',
    `ot_rate_multiplier` DECIMAL(18,2) COMMENT 'The pay rate multiplier applied to hours worked beyond the OT threshold. Standard FLSA rate is 1.5x (time-and-a-half); double-time (DT) states or contracts may require 2.0x. Used in payroll processing and timesheet OT rule configuration.',
    `ot_threshold_hours` DECIMAL(18,2) COMMENT 'The weekly (or daily, for states like California) hour threshold beyond which overtime pay is required for this worker. Standard federal FLSA threshold is 40 hours/week; California requires daily OT after 8 hours. Drives timesheet OT calculation rules.',
    `pay_equity_outcome` STRING COMMENT 'Result of the pay equity review for this worker engagement. compliant indicates no pay disparity found; gap_identified flags a potential pay equity issue requiring remediation; remediated indicates a gap was corrected; not_applicable when no pay equity review was required.. Valid values are `compliant|gap_identified|remediated|not_applicable`',
    `pay_equity_review_flag` BOOLEAN COMMENT 'Indicates whether a pay equity assessment was conducted as part of this determination. True triggers documentation of the pay equity analysis outcome. Supports EEOC and OFCCP pay equity compliance reporting.',
    `pay_rate_type` STRING COMMENT 'The compensation structure type for the validated pay rate. hourly for time-based workers; salary for exempt salaried employees; daily for day-rate engagements; piece_rate for output-based pay; per_diem for daily allowance-based arrangements. Affects overtime calculation methodology.. Valid values are `hourly|salary|daily|piece_rate|per_diem`',
    `pay_rate_validated` DECIMAL(18,2) COMMENT 'The workers pay rate (per hour) that was validated against applicable minimum wage, prevailing wage, or FLSA salary threshold requirements as part of this determination. Expressed in USD per hour. Core field for DOL audit readiness and pay equity assessments.',
    `prevailing_wage_flag` BOOLEAN COMMENT 'Indicates whether a prevailing wage requirement (Davis-Bacon Act for federal construction contracts or Service Contract Act for federal service contracts) applies to this worker engagement. True triggers prevailing wage rate validation.',
    `prevailing_wage_type` STRING COMMENT 'Specifies the prevailing wage framework applicable to this engagement. davis_bacon for federal construction projects; service_contract_act for federal service contracts; state_prevailing_wage for state-mandated prevailing wage laws; none when no prevailing wage applies.. Valid values are `davis_bacon|service_contract_act|state_prevailing_wage|none`',
    `review_trigger` STRING COMMENT 'The business event or reason that initiated this wage and hour determination. [ENUM-REF-CANDIDATE: new_placement|rate_change|law_change|periodic_review|dol_audit|client_request|worker_complaint — promote to reference product]',
    `salary_threshold_met` BOOLEAN COMMENT 'Indicates whether the workers salary meets the current FLSA minimum salary threshold required for white-collar exemption ($684/week as of 2024 federal standard). True is required for exempt classification under executive, administrative, or professional exemptions.',
    `sign_off_date` DATE COMMENT 'Date on which the compliance officer formally approved and signed off on this wage and hour determination. Required for DOL audit trail documentation.',
    `soc_code` STRING COMMENT 'Bureau of Labor Statistics Standard Occupational Classification code for the workers role. Used for prevailing wage determination lookups (Davis-Bacon, Service Contract Act wage schedules), EEOC occupational category reporting, and OFCCP compliance.. Valid values are `^d{2}-d{4}$`',
    `source_system` STRING COMMENT 'The operational system of record from which this determination was originated or validated. Supports data lineage tracking across the lakehouse silver layer.. Valid values are `TempWorks|Kronos|Bullhorn|SAP_SuccessFactors|Beeline|Manual`',
    `updated_timestamp` TIMESTAMP COMMENT 'Timestamp when this wage and hour determination record was most recently modified. Supports change tracking, audit trail requirements, and silver layer incremental processing.',
    `work_state` STRING COMMENT 'Two-letter US state code where the worker performs services. Determines applicable state minimum wage, state overtime rules, state prevailing wage laws, SUTA jurisdiction, and workers compensation requirements.. Valid values are `^[A-Z]{2}$`',
    CONSTRAINT pk_wage_hour_determination PRIMARY KEY(`wage_hour_determination_id`)
) COMMENT 'Master record for wage and hour compliance determinations made for worker engagements, covering FLSA overtime eligibility, state-specific minimum wage applicability, prevailing wage determinations (Davis-Bacon, Service Contract Act), exempt vs. non-exempt classification, and pay equity assessments. Captures determination date, applicable law/regulation, pay rate validated, overtime threshold, and compliance officer sign-off. Supports DOL audit readiness and FLSA litigation defense.';

CREATE OR REPLACE TABLE `staffing_hr_ecm_v1`.`compliance`.`requirement` (
    `requirement_id` BIGINT COMMENT 'Unique surrogate identifier for each compliance requirement record in the reference master catalog. Primary key for the compliance_requirement data product.',
    `client_account_id` BIGINT COMMENT 'Reference to the client account for whom this requirement is contractually mandated. Populated only when client_specific_flag is True. Links to the client account master for requirement-to-placement enforcement scoping.',
    `msa_id` BIGINT COMMENT 'Foreign key linking to contract.msa. Business justification: MSAs incorporate compliance requirements by reference (e.g., Supplier shall comply with all applicable federal contractor obligations). Real business need: MSA-driven requirement applicability for c',
    `credential_id` BIGINT COMMENT 'Foreign key linking to credentialing.credential. Business justification: Compliance requirements define which credentials are mandatory for regulatory compliance (e.g., state-specific licenses, federal contractor requirements). Business process: Compliance rule engine maps',
    `ic_agreement_id` BIGINT COMMENT 'Foreign key linking to contract.ic_agreement. Business justification: IC-specific compliance requirements (insurance minimums, 1099 reporting, background checks) are contractually mandated in ic_agreements. Staffing compliance teams must link requirements to the governi',
    `location_id` BIGINT COMMENT 'Foreign key linking to client.location. Business justification: Compliance requirements are often site-specific — city-level paid leave posting, site-specific safety training mandates, or union-site requirements. Linking requirement to location enables automated c',
    `managed_program_id` BIGINT COMMENT 'Foreign key linking to client.managed_program. Business justification: MSP managed programs define program-specific compliance requirements (e.g., mandatory drug screens, specific BGC tiers, EOR requirements). Linking requirement to managed_program enables program-level ',
    `sow_id` BIGINT COMMENT 'Foreign key linking to contract.sow. Business justification: SOWs specify engagement-specific requirements (e.g., All workers on this SOW must hold Secret clearance). Real business need: SOW-level requirement tracking for engagement-specific compliance.',
    `state_compliance_rule_id` BIGINT COMMENT 'Foreign key linking to compliance.state_compliance_rule. Business justification: When a compliance requirement is state-specific (jurisdiction_scope = state/local), it references the specific state compliance rule. This creates a 1:N relationship where one state rule can be refere',
    `superseded_by_requirement_id` BIGINT COMMENT 'Reference to the compliance_requirement_id of the newer requirement that replaces this record when status is superseded. Enables forward-chaining of requirement version history for audit and compliance lineage.',
    `vendor_agreement_id` BIGINT COMMENT 'Foreign key linking to contract.vendor_agreement. Business justification: Compliance requirements (background check standards, drug screen panels, everify mandates) are contractually specified in vendor_agreements. Staffing vendor onboarding and compliance monitoring requir',
    `applicable_placement_type` STRING COMMENT 'Specifies which placement types this requirement governs (e.g., temporary, permanent, contract_to_hire, direct_placement, all). Drives requirement-to-placement enforcement checks in the compliance engine. [ENUM-REF-CANDIDATE: temporary|permanent|contract_to_hire|direct_placement|temp_to_perm|sow|all — promote to reference product]',
    `applicable_worker_type` STRING COMMENT 'Specifies which worker classification this requirement applies to: W-2 employees, 1099 independent contractors (IC), both, or all workers regardless of classification. Critical for FLSA worker classification enforcement and IRS co-employment risk management.. Valid values are `w2_employee|1099_contractor|both|all_workers`',
    `applies_to_offboarding` BOOLEAN COMMENT 'Indicates whether this requirement must be fulfilled during the worker offboarding process (True), such as final I-9 retention checks, COBRA notification, or non-compete enforcement at assignment end.',
    `applies_to_onboarding` BOOLEAN COMMENT 'Indicates whether this requirement must be fulfilled during the worker onboarding process (True). Drives onboarding checklist generation in SAP SuccessFactors and Bullhorn ATS/CRM for new placements.',
    `audit_trail_required` BOOLEAN COMMENT 'Indicates whether this requirement mandates a formal audit trail of compliance actions (True). When True, all enforcement checks, document submissions, and status changes must be logged for DOL, OSHA, IRS, or EEOC audit defense purposes.',
    `client_specific_flag` BOOLEAN COMMENT 'Indicates whether this requirement is specific to a particular clients contractual mandate (True) rather than a universal federal or industry standard (False). Client-specific requirements are typically defined in the clients MSA or SOW.',
    `compliance_frequency` STRING COMMENT 'How often this requirement must be fulfilled or re-verified: one_time (at hire/placement), per_placement (each new assignment), annual (yearly renewal), quarterly, monthly, or ongoing (continuous monitoring). Drives scheduling of compliance checks.. Valid values are `one_time|per_placement|annual|quarterly|monthly|ongoing`',
    `compliance_owner_role` STRING COMMENT 'The organizational role responsible for ensuring this requirement is met and enforced (e.g., compliance_team, legal_counsel, hr_operations, recruiter, branch_manager, payroll_team). Used for workflow routing and accountability assignment.. Valid values are `compliance_team|legal_counsel|hr_operations|recruiter|branch_manager|payroll_team`',
    `created_timestamp` TIMESTAMP COMMENT 'The timestamp when this compliance requirement record was first created in the system. Supports audit trail, data lineage, and SOC 2 Type II compliance logging.',
    `effective_date` DATE COMMENT 'The date on which this compliance requirement becomes binding and enforceable for Staffing Hr operations. Used to determine which requirements apply to placements and assignments active on or after this date.',
    `enforcement_action_required` STRING COMMENT 'Specifies the system or operational action to take when this requirement is not met: block_placement (prevent assignment activation), notify_compliance (alert compliance team), flag_for_review (queue for manual review), document_only (record non-compliance without blocking), escalate_to_legal (route to legal counsel).. Valid values are `block_placement|notify_compliance|flag_for_review|document_only|escalate_to_legal`',
    `expiration_date` DATE COMMENT 'The date on which this compliance requirement ceases to be enforceable or is superseded. Null indicates the requirement is open-ended with no defined expiration. Used to filter active requirements in enforcement checks.',
    `external_reference_url` STRING COMMENT 'URL link to the official regulatory text, governing body publication, or client contract clause that defines this requirement (e.g., link to eCFR, EEOC.gov guidance, OSHA standard). Enables compliance officers to access authoritative source documentation.',
    `federal_contractor_applicable` BOOLEAN COMMENT 'Indicates whether this requirement applies specifically or additionally to federal contractor placements (True), as governed by OFCCP, E-Verify Executive Order 13465, or FAR clauses. Drives enhanced compliance checks for federal contract assignments.',
    `governing_body` STRING COMMENT 'The regulatory authority, agency, or organization that issued or enforces this requirement (e.g., U.S. Department of Labor, EEOC, OSHA, OFCCP, IRS, ASA, SHRM, USCIS). Used for audit trail and regulatory reporting alignment.',
    `grace_period_days` STRING COMMENT 'Number of calendar days after a triggering event (e.g., hire date, placement start) within which this requirement must be fulfilled before enforcement action is triggered. For example, I-9 must be completed within 3 business days of hire.',
    `industry_sector_scope` STRING COMMENT 'Specifies the industry sector(s) to which this requirement applies (e.g., Healthcare, Finance, Government, All). Some compliance requirements are sector-specific (e.g., OSHA 300 log for manufacturing, drug screening for DOT-regulated industries). Pipe-delimited for multi-sector applicability.',
    `job_category_scope` STRING COMMENT 'Specifies the job categories or occupational classifications to which this requirement applies (e.g., All, CDL Drivers, Healthcare Workers, IT Professionals). Drives targeted enforcement for role-specific compliance mandates such as drug screening or credentialing.',
    `jurisdiction_scope` STRING COMMENT 'Geographic or contractual scope of applicability for this requirement: federal (applies nationwide), state (applies within specific states — detail in state_compliance_rule), local (city/county level), client_specific (applies only to placements under a specific client contract), international (GDPR, CCPA cross-border), multi_jurisdiction (spans multiple levels).. Valid values are `federal|state|local|client_specific|international|multi_jurisdiction`',
    `mandatory_documentation_checklist` STRING COMMENT 'Pipe-delimited or structured list of required documents that must be collected and retained to satisfy this compliance requirement (e.g., I-9 Form|Passport Copy|E-Verify Case Number or EEO-1 Report|Workforce Census Data). Drives document collection workflows in onboarding and placement management.',
    `notes` STRING COMMENT 'Free-text field for compliance officers to record additional context, interpretive guidance, exceptions, or pending regulatory changes related to this requirement. Not used for structured enforcement logic.',
    `penalty_amount_max` DECIMAL(18,2) COMMENT 'Maximum monetary penalty (in USD) that can be assessed per violation of this requirement, as published by the governing regulatory body. Used in risk scoring and compliance prioritization. Expressed in USD.',
    `penalty_description` STRING COMMENT 'Narrative description of the regulatory or contractual penalties for failing to meet this requirement (e.g., Civil penalty up to $2,320 per I-9 violation per USCIS schedule, Contract termination per MSA Section 12.3). Used in risk assessment and compliance training.',
    `re_verification_interval_days` STRING COMMENT 'Number of days between required re-verifications when re_verification_required is True. Used to calculate next due dates for compliance tracking and automated reminders. Null when re_verification_required is False.',
    `re_verification_required` BOOLEAN COMMENT 'Indicates whether this compliance requirement mandates periodic re-verification or renewal (True) or is satisfied once at initial compliance (False). For example, I-9 re-verification for workers with temporary employment authorization.',
    `regulatory_citation` STRING COMMENT 'Specific legal or regulatory citation for this requirement (e.g., 8 U.S.C. § 1324a, 29 CFR Part 1602, 29 CFR 1904, IRC § 3401, FLSA 29 U.S.C. § 201). Enables precise legal traceability and audit defense.',
    `requirement_category` STRING COMMENT 'Functional compliance domain grouping this requirement belongs to (e.g., I-9 / E-Verify, EEOC Reporting, OFCCP Reporting, FLSA Classification, OSHA Safety, Background Check / FCRA, Co-Employment Risk, Non-Compete / NDA, Tax / IRS, Workers Compensation). Drives requirement-to-enforcement routing. [ENUM-REF-CANDIDATE: i9_everify|eeoc_reporting|ofccp_reporting|flsa_classification|osha_safety|bgc_fcra|co_employment|non_compete_nda|tax_irs|workers_comp — promote to reference product]',
    `requirement_code` STRING COMMENT 'Externally-known, human-readable unique code identifying this compliance requirement (e.g., I9-FED-001, EEOC-RPT-002, OSHA-300-LOG). Used as the business key across systems and in compliance checklists.. Valid values are `^[A-Z0-9_-]{3,30}$`',
    `requirement_description` STRING COMMENT 'Full narrative description of the compliance requirement, including what is mandated, who it applies to, and the business process it governs. Serves as the authoritative definition in the compliance rule catalog for enforcement checks and training.',
    `requirement_name` STRING COMMENT 'Short, human-readable title of the compliance requirement (e.g., I-9 Employment Eligibility Verification, EEOC Annual EEO-1 Report, FLSA Worker Classification Determination). Used in dashboards, checklists, and audit reports.',
    `requirement_status` STRING COMMENT 'Current lifecycle state of this compliance requirement record: active (currently enforceable), inactive (no longer applicable), pending_review (under legal/compliance review), superseded (replaced by a newer version), draft (not yet published for enforcement).. Valid values are `active|inactive|pending_review|superseded|draft`',
    `requirement_type` STRING COMMENT 'Categorical classification of the requirement source: federal_regulation (mandated by U.S. federal law), client_contractual (mandated by client MSA/SOW), industry_standard (ASA, SIA, SHRM best practice), state_regulation (state-level law — note: detailed state rules live in state_compliance_rule), internal_policy (Staffing Hr internal mandate).. Valid values are `federal_regulation|client_contractual|industry_standard|state_regulation|internal_policy`',
    `retention_period_years` STRING COMMENT 'Number of years that compliance documentation for this requirement must be retained per regulatory mandate (e.g., I-9 forms must be retained for 3 years after hire or 1 year after termination, whichever is later; OSHA 300 logs for 5 years). Drives records management and data lifecycle policies.',
    `review_date` DATE COMMENT 'The next scheduled date for the compliance team to review this requirement for regulatory changes, updates, or continued applicability. Supports proactive compliance management and audit readiness.',
    `risk_level` STRING COMMENT 'Risk severity classification for non-compliance with this requirement: critical (immediate legal/financial exposure, placement must be blocked), high (significant regulatory risk), medium (moderate risk requiring timely remediation), low (administrative or best-practice requirement).. Valid values are `critical|high|medium|low`',
    `source_system` STRING COMMENT 'The operational system of record from which this compliance requirement was originated or is primarily managed (e.g., Bullhorn ATS/CRM, SAP SuccessFactors, DocuSign CLM). Supports data lineage and system-of-record traceability. [ENUM-REF-CANDIDATE: Bullhorn|SAP_SuccessFactors|DocuSign_CLM|Sterling_BGC|Beeline_VMS|Manual|Other — 7 candidates stripped; promote to reference product]',
    `training_course_reference` STRING COMMENT 'Identifier or name of the training course in the Learning Management System (LMS) that satisfies the training requirement for this compliance item. Populated when training_required is True. Links to SAP SuccessFactors LMS course catalog.',
    `training_required` BOOLEAN COMMENT 'Indicates whether completion of a specific training program is required to satisfy this compliance requirement (True). For example, OSHA safety training, EEOC harassment prevention training, or FLSA classification training for recruiters.',
    `updated_timestamp` TIMESTAMP COMMENT 'The timestamp when this compliance requirement record was most recently modified. Used to detect regulatory updates, track version changes, and support audit trail requirements.',
    `version_number` STRING COMMENT 'Version identifier for this compliance requirement record, incremented when the requirement is updated due to regulatory changes or policy revisions (e.g., 1.0, 2.3). Supports audit trail and version history tracking.. Valid values are `^d+.d+$`',
    CONSTRAINT pk_requirement PRIMARY KEY(`requirement_id`)
) COMMENT 'Reference master for federal regulations and client-specific contractual compliance requirements that govern staffing operations. Each record defines a requirement type (federal regulation, client contractual mandate, industry standard), applicable jurisdiction scope, effective date, expiration date, governing body, requirement description, and mandatory documentation checklist. Serves as the compliance rule catalog driving requirement-to-worker and requirement-to-placement enforcement checks. Distinct from state_compliance_rule which owns state-specific and local jurisdiction requirements that vary by geography.';

CREATE OR REPLACE TABLE `staffing_hr_ecm_v1`.`compliance`.`placement_compliance_check` (
    `placement_compliance_check_id` BIGINT COMMENT 'Unique system-generated identifier for each placement compliance gate-check record. Primary key for this transactional entity. Role: TRANSACTION_HEADER.',
    `assignment_id` BIGINT COMMENT 'Reference to the worker placement record for which this compliance check is being performed. Links the compliance gate-check to the specific assignment or direct hire placement in Bullhorn ATS.',
    `bgc_order_id` BIGINT COMMENT 'Foreign key linking to credentialing.bgc_order. Business justification: Placement compliance checks track BGC completion as a clearance requirement; natural FK to the actual BGC order. Business process: Pre-placement compliance clearance dashboard displays BGC order statu',
    `client_account_id` BIGINT COMMENT 'Reference to the client account for which the placement is being made. Enables client-specific compliance requirement validation and reporting.',
    `msa_id` BIGINT COMMENT 'Foreign key linking to contract.msa. Business justification: Pre-placement compliance checks validate MSA-mandated requirements (BGC, drug screen, E-Verify). Real business need: MSA-driven clearance gates for placement approval and client compliance.',
    `credential_package_id` BIGINT COMMENT 'Foreign key linking to credentialing.credential_package. Business justification: Placement compliance checks validate against a specific credentialing package required for the placement. Business process: Compliance clearance validates all credential requirements defined in the as',
    `credential_requirement_id` BIGINT COMMENT 'Foreign key linking to credentialing.credential_requirement. Business justification: The placement compliance check validates each client-defined credential requirement as a placement gate. Linking to the specific credential_requirement being checked enables drill-down from check stat',
    `drug_screen_id` BIGINT COMMENT 'Foreign key linking to credentialing.drug_screen. Business justification: Placement compliance checks track drug screen completion as a clearance requirement; natural FK to the actual drug screen record. Business process: Pre-placement compliance clearance requires drug scr',
    `everify_case_id` BIGINT COMMENT 'Foreign key linking to compliance.everify_case. Business justification: Placement compliance check references the E-Verify case for the worker. This normalizes everify_status which can be retrieved via JOIN to everify_case. Clear 1:N relationship - one placement check ref',
    `i9_verification_id` BIGINT COMMENT 'Foreign key linking to compliance.i9_verification. Business justification: Placement compliance check references the I-9 verification record for the worker. This normalizes i9_status and i9_completion_date which can be retrieved via JOIN to i9_verification. Clear 1:N relatio',
    `ic_agreement_id` BIGINT COMMENT 'Foreign key linking to contract.ic_agreement. Business justification: Placement compliance checks for IC workers validate against ic_agreement terms (background_check_required_flag, drug_screen_required_flag, insurance_required_flag). Staffing compliance teams must refe',
    `license_verification_id` BIGINT COMMENT 'Foreign key linking to credentialing.license_verification. Business justification: The placement compliance check tracks credential_verification_status — a denormalization of the license_verification outcome. Linking directly to the license_verification record enables compliance coo',
    `location_id` BIGINT COMMENT 'Foreign key linking to client.location. Business justification: Site-specific onboarding requirements (safety training, badge/access, parking, dress code, client-specific clearances) are tracked per location. Location_id FK enables site-level compliance clearance ',
    `managed_program_id` BIGINT COMMENT 'Foreign key linking to client.managed_program. Business justification: Placement compliance checks are executed within the context of a managed program whose rules govern required checks (BGC tier, drug screen panel, I-9 method). Program-level compliance pass/fail report',
    `order_header_id` BIGINT COMMENT 'Reference to the job order (requisition) associated with this placement compliance check. Enables traceability from compliance clearance back to the originating client requirement.',
    `position_requirement_id` BIGINT COMMENT 'Foreign key linking to joborder.position_requirement. Business justification: Placement compliance checks validate candidates against specific position requirements (bgc_type, drug_screen_panel, certifications, security_clearance_level, everify_required). The existing order_hea',
    `profile_id` BIGINT COMMENT 'Reference to the candidate (worker) who is the subject of this compliance check. Used to link compliance clearance to the individual worker record in Bullhorn ATS.',
    `requirement_id` BIGINT COMMENT 'Foreign key linking to compliance.requirement. Business justification: A placement compliance check verifies that a worker placement satisfies specific compliance requirements before the assignment begins. Adding requirement_id to placement_compliance_check links each ga',
    `skills_assessment_id` BIGINT COMMENT 'Foreign key linking to credentialing.skills_assessment. Business justification: For IT, healthcare, and finance placements, skills assessment is a mandatory compliance gate. The placement_compliance_check has no current link to skills_assessment despite tracking overall complianc',
    `sow_id` BIGINT COMMENT 'Foreign key linking to contract.sow. Business justification: SOW-specific clearance requirements (e.g., client-specific certifications). Real business need: SOW-level compliance gating for engagement-specific placement approval.',
    `state_compliance_rule_id` BIGINT COMMENT 'Foreign key linking to compliance.state_compliance_rule. Business justification: Placement compliance check validates against state-specific compliance rules. This normalizes state_compliance_jurisdiction which can be retrieved via JOIN to state_compliance_rule. Clear 1:N relation',
    `supplier_id` BIGINT COMMENT 'Foreign key linking to vendor.supplier. Business justification: Placement compliance checks are performed on workers supplied by a specific vendor. Linking directly to supplier enables supplier-level compliance dashboards, pass/fail rate reporting by vendor, and M',
    `training_record_id` BIGINT COMMENT 'Foreign key linking to credentialing.training_record. Business justification: placement_compliance_check has safety_training_date and safety_training_status — denormalized from training_record. Linking to training_record normalizes these fields and enables compliance checks to ',
    `vendor_agreement_id` BIGINT COMMENT 'Foreign key linking to contract.vendor_agreement. Business justification: Placement compliance checks for vendor-supplied workers must validate against vendor_agreement standards (background_check_standard, drug_screen_panel_type, everify_required_flag). Staffing operations',
    `vms_program_id` BIGINT COMMENT 'Foreign key linking to client.vms_program. Business justification: VMS programs define specific compliance gate rules (bgc_required, drug_screen_required, everify_required, ic_allowed). Linking placement_compliance_check to vms_program enables automated compliance ga',
    `wage_hour_determination_id` BIGINT COMMENT 'Foreign key linking to compliance.wage_hour_determination. Business justification: Placement compliance check references the wage and hour determination for the engagement. This normalizes wage_hour_determination_status which can be retrieved via JOIN to wage_hour_determination. Cle',
    `worker_classification_id` BIGINT COMMENT 'Foreign key linking to compliance.worker_classification. Business justification: Placement compliance check references the worker classification determination. This normalizes worker_classification and flsa_exemption_status which can be retrieved via JOIN to worker_classification.',
    `assignment_start_date` DATE COMMENT 'The scheduled or actual start date of the worker assignment or placement. Compliance clearance must be achieved prior to this date. Used to flag placements where clearance was obtained after assignment start.',
    `bgc_completion_date` DATE COMMENT 'The date on which the background check screening was completed and a final result was returned by Sterling Background Check. Used to assess BGC turnaround time and compliance with client SLA requirements.',
    `bgc_status` STRING COMMENT 'Status of the background check (BGC) screening for this placement as reported by Sterling Background Check. clear indicates no disqualifying findings. adverse_action indicates findings requiring pre-adverse and adverse action notices per FCRA. waived indicates client or internal authorization to proceed without BGC.. Valid values are `not_required|pending|clear|adverse_action|waived`',
    `blocking_check_count` STRING COMMENT 'Count of individual compliance check items that are currently in a failed or pending status that would block placement activation. A value of 0 with check_status = cleared confirms full compliance. Used in real-time compliance dashboards to prioritize remediation.',
    `check_initiated_date` DATE COMMENT 'The business date on which the compliance gate-check process was initiated for this placement. Represents the principal real-world event time for this transaction. Used to measure compliance processing cycle time and SLA adherence.',
    `check_reference_number` STRING COMMENT 'Externally-known business identifier for this compliance check record, used in audit trails, compliance dashboards, and cross-system references. Typically formatted as CHK-YYYY-NNNNNN.',
    `check_status` STRING COMMENT 'Overall lifecycle status of the placement compliance gate-check. cleared indicates all required checks passed and placement may go active. failed blocks placement from generating billable hours. waived indicates authorized exception granted. expired indicates a previously cleared check has lapsed and requires renewal.. Valid values are `pending|in_progress|cleared|failed|waived|expired`',
    `check_type` STRING COMMENT 'Classifies the nature of the compliance gate-check. initial applies to new placements, extension to assignment extensions, reactivation to returning workers, annual_renewal for ongoing long-term assignments, client_change when a worker transfers to a new client.. Valid values are `initial|extension|reactivation|annual_renewal|client_change`',
    `clearance_date` DATE COMMENT 'The date on which all required compliance checks were satisfied and the placement was granted compliance clearance to go active. Null if clearance has not yet been granted. Used to calculate time-to-clearance metrics.',
    `client_specific_req_status` STRING COMMENT 'Status of any additional compliance requirements mandated by the clients MSA or VMS program beyond standard federal and state requirements. Examples include client-specific background check panels, additional drug test panels, site-specific safety certifications, or vendor credentialing requirements in Beeline VMS.. Valid values are `not_required|pending|complete|failed|waived`',
    `compliance_notes` STRING COMMENT 'Free-text field for compliance team annotations, exception documentation, escalation notes, or additional context related to this placement compliance check. Supports audit trail and case management.',
    `created_timestamp` TIMESTAMP COMMENT 'The timestamp when this placement compliance check record was first created in the system. Provides audit trail for record origination and supports SOC 2 Type II audit logging requirements.',
    `credential_verification_status` STRING COMMENT 'Status of required professional credential and license verification for this placement. Applies to placements requiring specific certifications (e.g., nursing licenses, CDL, OSHA certifications, IT certifications). Verified through Sterling Background Check and internal credentialing processes.. Valid values are `not_required|pending|verified|failed|waived`',
    `drug_screen_date` DATE COMMENT 'The date on which the drug screen specimen was collected and/or the final result was reported. Used to validate that drug screening was completed within the required pre-placement window.',
    `drug_screen_status` STRING COMMENT 'Status of the pre-placement drug screening for this worker. negative clears the worker for placement. positive blocks placement and may trigger adverse action. not_required applies when client or placement type does not mandate drug screening. Managed through Sterling Background Check.. Valid values are `not_required|pending|negative|positive|waived`',
    `eeoc_self_id_collected` BOOLEAN COMMENT 'Indicates whether the EEOC voluntary self-identification form (race, ethnicity, gender, disability, veteran status) has been collected from the worker for this placement. Required for EEOC and OFCCP reporting compliance for federal contractor clients.',
    `noncompete_nda_check_status` STRING COMMENT 'Status of the review for existing non-compete agreements and NDAs that could restrict the workers placement with the target client. conflict_identified requires legal review before placement proceeds. Tracked via DocuSign CLM.. Valid values are `not_required|pending|clear|conflict_identified|waived`',
    `ofccp_applicability_flag` BOOLEAN COMMENT 'Indicates whether this placement is subject to OFCCP affirmative action and equal employment opportunity requirements because the client is a federal contractor or subcontractor. Drives additional compliance obligations including AAP tracking and adverse impact analysis.',
    `onboarding_status` STRING COMMENT 'Status of the worker onboarding process in SAP SuccessFactors, including completion of required forms, policy acknowledgments, direct deposit setup, and benefits enrollment. complete is required before a placement can generate billable hours.. Valid values are `not_started|in_progress|complete|waived`',
    `overall_compliance_result` STRING COMMENT 'The final aggregated compliance determination for this placement. pass authorizes the placement to go active and generate billable hours. fail blocks activation. conditional_pass indicates clearance granted with documented exceptions or waivers. pending_review indicates escalation to compliance team.. Valid values are `pass|fail|conditional_pass|pending_review`',
    `placement_type` STRING COMMENT 'The type of placement being compliance-checked. Determines which compliance requirements are applicable (e.g., I-9 requirements differ for SOW vs. direct placement; workers comp requirements differ for temporary vs. direct hire). [ENUM-REF-CANDIDATE: temporary|contract_to_hire|direct_placement|per_diem|sow|rpo — promote to reference product]. Valid values are `temporary|contract_to_hire|direct_placement|per_diem|sow`',
    `source_system` STRING COMMENT 'The operational system of record from which this compliance check record originated or was primarily managed. Supports data lineage tracking in the Silver layer lakehouse and cross-system reconciliation.. Valid values are `bullhorn|sap_successfactors|sterling|beeline_vms|docusign_clm|manual`',
    `updated_timestamp` TIMESTAMP COMMENT 'The timestamp when this placement compliance check record was most recently modified. Tracks the latest state change for audit trail purposes and supports incremental data loading in the Databricks Silver layer.',
    `waiver_authorization` STRING COMMENT 'Name or identifier of the authorized approver who granted a compliance waiver for this placement (if applicable). Required when check_status = waived or overall_compliance_result = conditional_pass. Provides audit trail for waiver accountability.',
    `waiver_expiry_date` DATE COMMENT 'The date on which a granted compliance waiver expires. After this date, the outstanding compliance item must be completed or the placement may be suspended. Drives automated compliance expiry alerts.',
    `waiver_reason` STRING COMMENT 'Documented business justification for any compliance waiver granted for this placement. Required for audit trail integrity. Examples include client-approved exceptions, emergency placements with post-start completion commitments, or regulatory exemptions.',
    `workers_comp_code` STRING COMMENT 'The NCCI workers compensation classification code assigned to this placement based on the job duties and work environment. Drives workers comp premium calculation in TempWorks Payroll and ensures correct coverage is in place before assignment start.',
    CONSTRAINT pk_placement_compliance_check PRIMARY KEY(`placement_compliance_check_id`)
) COMMENT 'Transactional record capturing the compliance gate-check results for each worker placement prior to assignment start or extension. Validates that all applicable federal, state, and client-specific compliance requirements are satisfied: I-9 complete, E-Verify authorized, BGC cleared, drug screen passed, required credentials verified, safety training complete, worker classification determined, co-employment risk assessed, wage and hour determination completed, and client-specific requirements met. Each check item has a pass/fail/waived/pending status, check date, reviewer, and waiver authorization (if applicable). Acts as the compliance clearance record before a placement goes active. Supports real-time compliance dashboards and prevents non-compliant placements from generating billable hours.';

CREATE OR REPLACE TABLE `staffing_hr_ecm_v1`.`compliance`.`state_compliance_rule` (
    `state_compliance_rule_id` BIGINT COMMENT 'Unique identifier for the state-specific compliance rule record. Primary key.',
    `credential_requirement_id` BIGINT COMMENT 'Foreign key linking to credentialing.credential_requirement. Business justification: State compliance rules (licensing laws, AB5, state drug testing mandates) directly mandate specific credential requirements for placements in that jurisdiction. Linking state_compliance_rule to creden',
    `primary_superseded_by_rule_state_compliance_rule_id` BIGINT COMMENT 'Reference to the state_compliance_rule_id of the newer rule that supersedes this rule. Null if this rule is current and not superseded.',
    `template_id` BIGINT COMMENT 'Foreign key linking to contract.template. Business justification: State compliance rules directly drive contract template clause selection (includes_flsa_compliance_clause, includes_eeoc_compliance_clause, includes_workers_comp_clause). Staffing contract teams must ',
    `applicability_criteria` STRING COMMENT 'Detailed business logic and conditions that determine when this compliance rule must be applied, including employer size, industry, worker type, and other qualifying factors.',
    `applicable_industry_sector` STRING COMMENT 'Industry sector or North American Industry Classification System (NAICS) code range to which this rule applies. Null if applies to all industries.',
    `applicable_worker_type` STRING COMMENT 'Type of worker classification to which this compliance rule applies (e.g., all workers, W-2 only, 1099 independent contractors, temporary placements). [ENUM-REF-CANDIDATE: all|W-2|1099|temporary|permanent|contract|direct hire|temp-to-perm — 8 candidates stripped; promote to reference product]',
    `compliance_notes` STRING COMMENT 'Free-text field for internal compliance team notes, implementation guidance, or special considerations for this state rule.',
    `created_timestamp` TIMESTAMP COMMENT 'Timestamp when this state compliance rule record was first created in the system.',
    `documentation_required` STRING COMMENT 'Description of documentation, records, or forms that must be maintained to demonstrate compliance with this state rule.',
    `effective_date` DATE COMMENT 'Date when the state compliance rule becomes legally enforceable and must be applied to staffing operations.',
    `employer_size_threshold` STRING COMMENT 'Minimum number of employees or Full-Time Equivalents (FTE) that triggers applicability of this compliance rule. Null if applies to all employer sizes.',
    `enforcement_agency` STRING COMMENT 'Name of the state or local government agency responsible for enforcing this compliance rule (e.g., California Labor Commissioner, New York Department of Labor).',
    `expiration_date` DATE COMMENT 'Date when the state compliance rule ceases to be enforceable. Null for rules with no sunset provision.',
    `ic_test_type` STRING COMMENT 'Type of legal test used by this jurisdiction to determine independent contractor classification (e.g., ABC test in California, common law test in other states). Only applicable for independent contractor classification rules.. Valid values are `ABC test|common law test|hybrid test|not applicable`',
    `jurisdiction_level` STRING COMMENT 'Geographic scope level of the compliance rule indicating whether it applies at state, county, city, or municipal level.. Valid values are `state|county|city|municipal`',
    `jurisdiction_locality` STRING COMMENT 'City, county, or local jurisdiction name where this rule applies if more granular than state-level (e.g., San Francisco, Cook County). Null for state-wide rules.',
    `jurisdiction_state` STRING COMMENT 'Two-letter state abbreviation where this compliance rule applies (e.g., CA, NY, TX).. Valid values are `^[A-Z]{2}$`',
    `last_review_date` DATE COMMENT 'Date when this compliance rule was last reviewed by the compliance team to verify accuracy and currency.',
    `next_review_date` DATE COMMENT 'Scheduled date for the next periodic review of this compliance rule to ensure it remains current with legislative changes.',
    `penalty_amount_max` DECIMAL(18,2) COMMENT 'Maximum monetary penalty amount in USD that may be assessed for violation of this compliance rule. Null if no maximum specified.',
    `penalty_amount_min` DECIMAL(18,2) COMMENT 'Minimum monetary penalty amount in USD that may be assessed for violation of this compliance rule. Null if no minimum specified.',
    `penalty_description` STRING COMMENT 'Description of penalties, fines, or sanctions that may be imposed for non-compliance with this state rule.',
    `penalty_per_violation` BOOLEAN COMMENT 'Indicates whether penalties are assessed per individual violation (True) or as a single penalty regardless of violation count (False).',
    `posting_requirement` BOOLEAN COMMENT 'Indicates whether this compliance rule requires physical posting of notices at worksites or inclusion in job postings (True) or not (False).',
    `preempts_local_law` BOOLEAN COMMENT 'Indicates whether this state-level rule preempts or supersedes more restrictive local ordinances (True) or allows local jurisdictions to impose stricter requirements (False).',
    `regulatory_citation` STRING COMMENT 'Official legal citation to the statute, regulation, or ordinance that establishes this compliance requirement (e.g., California Labor Code Section 432.3).',
    `requirement_description` STRING COMMENT 'Comprehensive description of what the compliance rule requires staffing operations to do or prohibits them from doing.',
    `requirement_type` STRING COMMENT 'Category of state-specific compliance requirement. [ENUM-REF-CANDIDATE: ban-the-box|pay transparency|salary history ban|state e-verify mandate|drug testing restriction|portable background check|paid sick leave mandate|predictive scheduling|wage theft prevention notice|state mini-WARN|independent contractor test variation|workers comp mandate|unemployment insurance requirement|disability insurance requirement|family leave mandate — promote to reference product]',
    `retention_period_years` STRING COMMENT 'Number of years that documentation related to this compliance rule must be retained. Null if no specific retention period mandated.',
    `risk_level` STRING COMMENT 'Internal risk rating assigned to this compliance rule based on penalty severity, enforcement frequency, and business impact of non-compliance.. Valid values are `critical|high|medium|low`',
    `rule_code` STRING COMMENT 'Business identifier for the state compliance rule, typically formatted as state abbreviation followed by rule category code (e.g., CA-BTB001 for California Ban-the-Box).. Valid values are `^[A-Z]{2}-[A-Z0-9]{3,10}$`',
    `rule_name` STRING COMMENT 'Human-readable name of the state compliance rule (e.g., California Ban-the-Box Law, New York Salary Transparency Act).',
    `rule_status` STRING COMMENT 'Current lifecycle status of the state compliance rule indicating whether it is currently enforceable.. Valid values are `active|pending|expired|superseded|repealed|suspended`',
    `source_url` STRING COMMENT 'Web URL link to the authoritative source document, legislative text, or regulatory guidance for this compliance rule.. Valid values are `^https?://.*$`',
    `training_required` BOOLEAN COMMENT 'Indicates whether this compliance rule mandates specific training for recruiters, managers, or workers (True) or not (False).',
    `updated_timestamp` TIMESTAMP COMMENT 'Timestamp when this state compliance rule record was last modified in the system.',
    `version_number` STRING COMMENT 'Version identifier for this compliance rule, incremented when amendments or updates are made to the underlying statute or regulation.. Valid values are `^[0-9]+.[0-9]+$`',
    CONSTRAINT pk_state_compliance_rule PRIMARY KEY(`state_compliance_rule_id`)
) COMMENT 'Reference master for state-specific and local jurisdiction compliance requirements that vary by geography and impact multi-state staffing operations. Captures state/locality, effective date, expiration date, requirement type (ban-the-box, pay transparency, salary history ban, state E-Verify mandate, state-specific drug testing restrictions, portable background check laws, paid sick leave mandate, predictive scheduling, wage theft prevention notice, state mini-WARN Act, independent contractor classification test variations such as ABC test vs. common law test), applicability criteria (employer size threshold, industry sector, worker type), penalty for non-compliance, enforcement agency, and source citation with URL. Drives jurisdiction-aware compliance enforcement for multi-state staffing operations. Distinct from compliance_requirement which owns federal regulations and client-specific contractual mandates.';

